import React from 'react';
import { useNavigate } from 'react-router-dom';
import { LANGUAGES, TRANSLATIONS } from '../constants';
import { Language } from '../types';
import { 
  BellIcon, 
  InformationCircleIcon, 
  StarIcon,
  SunIcon,
  MoonIcon
} from '@heroicons/react/24/solid';

const Settings: React.FC<any> = ({ language, setLanguage, fontSize, setFontSize, darkMode, setDarkMode }) => {
  const navigate = useNavigate();
  const t = TRANSLATIONS[language];

  const SettingItem = ({ icon: Icon, title, subtitle, onClick, value, customIcon, toggle }: any) => (
    <div 
      onClick={onClick}
      className={`w-full bg-[#111] dark:bg-zinc-900/50 rounded-2xl p-5 mb-4 flex items-center border border-zinc-800 transition-all ${onClick ? 'active:scale-[0.98] cursor-pointer' : ''}`}
    >
      <div className="w-12 h-12 bg-[#0ea5e9] rounded-full flex items-center justify-center flex-shrink-0 shadow-lg shadow-sky-500/20">
        {customIcon ? customIcon : <Icon className="w-6 h-6 text-white" />}
      </div>
      <div className="ml-5 flex-grow text-left">
        <h3 className="text-xl font-bold text-white tracking-tight">{title}</h3>
        {subtitle && <p className="text-sm text-zinc-500 font-medium">{subtitle}</p>}
      </div>
      {value && <span className="text-zinc-400 mr-2">{value}</span>}
      {toggle && (
        <button 
          onClick={(e) => { e.stopPropagation(); toggle.onToggle(); }}
          className={`w-14 h-8 rounded-full relative transition-colors duration-300 ${
            toggle.isActive ? 'bg-[#0ea5e9]' : 'bg-zinc-700'
          }`}
        >
          <div className={`absolute top-1/2 -translate-y-1/2 w-6 h-6 rounded-full bg-white transition-all duration-300 shadow-md ${
            toggle.isActive ? 'right-1' : 'left-1'
          }`} />
        </button>
      )}
    </div>
  );

  return (
    <div className="max-w-xl mx-auto min-h-screen bg-black transition-colors duration-300 pb-32">
      {/* Distinctive Sky Blue Header from Screenshot */}
      <div className="relative pt-12 pb-16 px-6 overflow-hidden">
        <div 
          className="absolute inset-x-0 top-0 h-40 bg-[#0ea5e9] shadow-xl"
          style={{
            clipPath: 'polygon(0 0, 100% 0, 100% 80%, 90% 100%, 10% 100%, 0 80%)',
          }}
        />
        <div className="relative z-10 text-center">
          <h1 className="text-5xl font-serif-church font-medium text-white tracking-wide mt-4">Settings</h1>
        </div>
      </div>

      <div className="px-5 space-y-8 -mt-4">
        {/* Pill-shaped Language Selection Grid as seen in screenshot */}
        <div className="bg-[#111] p-2 border border-zinc-800 rounded-full flex items-center justify-between overflow-x-auto no-scrollbar">
          {LANGUAGES.map((lang) => (
            <button
              key={lang.id}
              onClick={() => setLanguage(lang.id as Language)}
              className={`whitespace-nowrap px-6 py-3 rounded-full text-lg font-bold transition-all duration-300 ${
                language === lang.id 
                  ? 'bg-[#0ea5e9] text-white shadow-lg' 
                  : 'text-zinc-500'
              }`}
            >
              {lang.label}
            </button>
          ))}
        </div>

        {/* Settings Cards */}
        <div className="pt-2">
          <SettingItem 
            icon={BellIcon} 
            title="Notification and Reminder" 
            onClick={() => navigate('/notifications')}
          />

          <SettingItem 
            icon={darkMode ? MoonIcon : SunIcon} 
            title={t.darkMode || 'Dark Mode'} 
            subtitle={darkMode ? 'Enabled' : 'Disabled'}
            toggle={{
              isActive: darkMode,
              onToggle: () => setDarkMode(!darkMode)
            }}
          />

          <div className="relative">
            <SettingItem 
              customIcon={(
                <div className="text-white font-black text-xl flex items-center justify-center">
                  <span className="leading-none">T</span>
                  <span className="text-sm leading-none mt-1">T</span>
                </div>
              )} 
              title={t.textSize}
            />
            <div className="px-6 pb-6 -mt-6">
               <input 
                type="range" 
                min="14" 
                max="32" 
                value={fontSize} 
                onChange={(e) => setFontSize(parseInt(e.target.value))}
                className="w-full h-1.5 bg-zinc-800 rounded-lg appearance-none cursor-pointer accent-[#0ea5e9]"
              />
            </div>
