          <SettingItem 
            icon={InformationCircleIcon} 
            title={t.aboutUs} 
            onClick={() => navigate('/about-us')}
          />

          <SettingItem 
            icon={StarIcon} 
            title={t.rateUs} 
            onClick={() => window.open('https://play.google.com/store/apps', '_blank')}
