import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { Language, Category } from '../types';
import { ChevronRightIcon, MagnifyingGlassIcon } from '@heroicons/react/24/outline';
import { TRANSLATIONS, RELIGIOUS_BANNER } from '../constants';

const Home: React.FC<{ language: Language; setLanguage: (lang: Language) => void }> = ({ language, setLanguage }) => {
  const navigate = useNavigate();
  const [showCategories, setShowCategories] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const t = TRANSLATIONS[language];

  const categories: Category[] = [
    { id: 'monasteries', title: { Amharic: 'ገዳማት', Geez: 'ገዳማት', Tigrinya: 'ገዳማት', English: 'Monasteries', AfaanOromo: 'Gadamootaa' } },
    { id: 'abnet', title: { Amharic: 'የአብነት ትምህርት', Geez: 'ትምህርተ ቤተ ክርስቲያን', Tigrinya: 'ትምህርቲ አብነት', English: 'Church Education', AfaanOromo: 'Barnoota Mana Kiristaanaa' } },
    { id: 'teachers', title: { Amharic: 'ታዋቂ መምህራን', Geez: 'ዐበይት መምህራን', Tigrinya: 'ዓበይቲ መምህራን', English: 'Great Teachers(Eminent Teachers)', AfaanOromo: 'Barsiisota Beekamoo'} },
    { id: 'holidays', title: { Amharic: 'በዓላት', Geez: 'በዓላት', Tigrinya: 'በዓላት', English: 'Holidays', AfaanOromo: 'Ayyaanota' } }
  ];

  const filteredCategories = useMemo(() => {
    if (!searchQuery.trim()) return categories;
    const query = searchQuery.toLowerCase();
    return categories.filter(cat => 
      cat.title[language].toLowerCase().includes(query)
    );
  }, [categories, searchQuery, language]);

  const handleLanguageSelect = (lang: Language) => {
    setLanguage(lang);
    setShowCategories(true);
  };

  const languageOptions = [
    { id: 'Amharic' as Language, label: 'አማርኛ' },
    { id: 'Geez' as Language, label: 'ግዕዝ' },
    { id: 'Tigrinya' as Language, label: 'ትግርኛ' },
    { id: 'English' as Language, label: 'English' },
    { id: 'AfaanOromo' as Language, label: 'Afaan Oromo' },
  ];

  return (
    <div className="max-w-xl mx-auto min-h-screen bg-white transition-colors duration-300">
      {/* Top Banner Area */}
      <div className="relative w-full h-[28vh] overflow-hidden rounded-b-[2.5rem] shadow-2xl mb-8">
        <img 
          src={RELIGIOUS_BANNER} 
          className="w-full h-full object-cover object-center" 
          alt="Church Header" 
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/20 via-transparent to-transparent"></div>
      </div>

      {!showCategories ? (
        <div className="px-6 space-y-4 pb-32 animate-in fade-in slide-in-from-bottom-5 duration-700">
          {languageOptions.map((opt) => (
            <button
              key={opt.id}
              onClick={() => handleLanguageSelect(opt.id)}
              className="w-full flex items-center justify-between p-6 bg-white rounded-2xl shadow-sm border border-gray-100 hover:shadow-lg active:scale-[0.98] transition-all group"
            >
              <span className="text-2xl font-serif-church font-medium text-black group-hover:text-[#0ea5e9] transition-colors">
                {opt.label}
              </span>
              <ChevronRightIcon className="w-5 h-5 text-zinc-300 group-hover:text-[#0ea5e9] transition-colors" strokeWidth={3} />
            </button>
          ))}
        </div>
      ) : (
        <div className="px-6 space-y-5 pb-32 animate-in fade-in duration-500">
          <div className="flex items-center justify-between mb-2 px-1">
            <h2 className="text-2xl font-black text-[#0ea5e9] tracking-tight">{t.categories}</h2>
            <button 
              onClick={() => setShowCategories(false)}
              className="text-[11px] font-black text-zinc-400 hover:text-black transition-colors uppercase tracking-[0.1em] border border-gray-200 px-4 py-2 rounded-full bg-white shadow-sm"
            >
              {t.changeLanguage}
            </button>
          </div>

          {/* Search Bar */}
          <div className="relative group">
            <MagnifyingGlassIcon className="w-5 h-5 absolute left-4 top-1/2 -translate-y-1/2 text-zinc-400 group-focus-within:text-[#0ea5e9] transition-colors" />
            <input 
              type="text" 
              placeholder="Search" 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-12 pr-4 py-4 bg-white text-black rounded-2xl border border-gray-100 focus:outline-none focus:ring-1 focus:ring-[#0ea5e9] font-bold text-sm shadow-md placeholder:text-zinc-400"
            />
          </div>

          <div className="space-y-4">
            {filteredCategories.map((cat) => (
              <button
                key={cat.id}
                onClick={() => navigate(`/content/${cat.id}`)}
                className="w-full flex items-center justify-between p-6 bg-white rounded-[1.5rem] shadow-sm border border-gray-100 hover:shadow-lg active:scale-[0.98] transition-all group"
              >
                <div className="text-left">
                  <span className="text-lg font-black text-black group-hover:text-[#0ea5e9] transition-colors leading-tight tracking-tight">
                    {cat.title[language]}
                  </span>
                </div>
                <div className="text-[#0ea5e9] transition-transform group-hover:translate-x-1">
                  <ChevronRightIcon className="w-6 h-6" strokeWidth={3} />
                </div>
              </button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default Home;

