import React, { useState, useEffect, useMemo } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { ChevronLeftIcon, MagnifyingGlassIcon, ChevronRightIcon } from '@heroicons/react/24/solid';
import { GoogleGenAI, Type } from '@google/genai';
import { Language } from '../types';
import { TRANSLATIONS } from '../constants';

interface ContentDetailProps {
  language: Language;
  fontSize: number;
  isBible?: boolean;
}

const ContentDetail: React.FC<ContentDetailProps> = ({ language, fontSize, isBible }) => {
  const { categoryId, bookName } = useParams<{ categoryId?: string; bookName?: string }>();
  const navigate = useNavigate();
  const location = useLocation();
  const t = TRANSLATIONS[language];

  const [list, setList] = useState<any[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedItem, setSelectedItem] = useState<string | null>(null);
  const [detailContent, setDetailContent] = useState<string>('');
  const [imageUrl, setImageUrl] = useState<string>('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const queryParam = params.get('query');

    if (queryParam) {
      handleSelectItem(queryParam);
    } else if (isBible) {
      fetchBibleDetail();
    } else {
      fetchCategoryList();
    }
  }, [categoryId, bookName, language, isBible, location.search]);

  const fetchBibleDetail = async () => {
    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const promptText = `Provide a comprehensive theological and historical overview of the Bible book "${bookName}" in ${language}. Include major themes and its usage in the Ethiopian Orthodox Church. Include specific historical context about how this book was translated into Ge'ez.`;
      const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: promptText });
      setDetailContent(response.text || '');
      setImageUrl(`https://images.unsplash.com/photo-1507434965515-61970f2bd7c6?q=80&w=1200&auto=format&fit=crop`);
    } catch (e) { console.error(e); } finally { setLoading(false); }
  };

  const fetchCategoryList = async () => {
    if (!categoryId || categoryId === 'search') return;
    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const promptText = `Provide a list of 15 major entries for "${categoryId}" (Monasteries, Teachers, Holidays, or Church Education) in the Ethiopian Orthodox Church tradition.
      Include founding dates for monasteries, short life context for teachers, and origin context for holidays.
      Return as JSON: [{"name": "...", "description": "...", "year": "...", "searchTerms": "..."}] in ${language}. 
      The 'searchTerms' should be English keywords that would find a VIVID, REAL photo of this item on a site like Unsplash.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: promptText,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                year: { type: Type.STRING },
                searchTerms: { type: Type.STRING }
              },
              required: ["name", "description", "searchTerms"]
            }
          }
        }
      });
      setList(JSON.parse(response.text || '[]'));
    } catch (e) { console.error(e); } finally { setLoading(false); }
  };

  const handleSelectItem = async (itemName: string) => {
    setSelectedItem(itemName);
    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const promptText = `Provide a deep, realistic, and detailed profile of "${itemName}" for the Ethiopian Orthodox Church in ${language}.
      - If it's a teacher: Write a full Life History (የሕይወት ታሪክ). Focus on their moral guidance and legacy.
      - If it's a monastery: Write its full founding history (መቼ እንደተመሰረተ), specific location, architectural style, and spiritual significance.
      - If it's a holiday: Write its full Origin Story (መቼ እና የት መከበር እንደጀመረ), its scriptural basis, and how it is celebrated with vivid detail.
      - If it's Church Education: Write about its stages (Nebab, Zema, Qine, Metsehaf) with historical transmission details.
      Use Markdown headers for each section. Respond only with the content in ${language}. At the very end, add a line starting with 'IMAGE_TAGS:' followed by 3 descriptive English keywords for this item.`;

      const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: promptText });
      const text = response.text || '';

      const tagsMatch = text.match(/IMAGE_TAGS:\s*(.*)/i);
      const cleanContent = text.replace(/IMAGE_TAGS:\s*(.*)/i, '').trim();
      setDetailContent(cleanContent);

      let keywords = tagsMatch ? tagsMatch[1] : itemName;
      if (categoryId === 'monasteries') keywords += ", ancient ethiopian monastery, landscape";
      if (categoryId === 'teachers') keywords += ", ethiopian orthodox priest, iconography, portrait";
      if (categoryId === 'holidays') keywords += ", ethiopian celebration, religious festival, colorful";
      if (categoryId === 'abnet') keywords += ", ancient manuscripts, orthodox education";

      setImageUrl(`https://loremflickr.com/1200/800/${encodeURIComponent(keywords)}/all`);
    } catch (e) { console.error(e); } finally { setLoading(false); }
  };

  const filteredList = useMemo(() => {
    if (!searchQuery.trim()) return list;
    return list.filter(item => item.name.toLowerCase().includes(searchQuery.toLowerCase()));
  }, [list, searchQuery]);

  return (
    <div className="max-w-xl mx-auto min-h-screen bg-white transition-colors duration-300 pb-32 shadow-2xl">
      {/* Header in Sky Blue */}
      <div className="sticky top-0 bg-[#0ea5e9] text-white px-6 py-10 flex items-center shadow-xl z-50 rounded-b-[2.5rem]">
        <button 
          onClick={() => selectedItem ? setSelectedItem(null) : navigate(-1)} 
          className="mr-5 p-2.5 hover:bg-white/20 rounded-full transition-colors active:scale-90"
        >
          <ChevronLeftIcon className="w-6 h-6" />
        </button>
        <h1 className="text-2xl font-black truncate tracking-tight uppercase leading-none">
          {selectedItem || bookName || (categoryId ? t[categoryId] : 'History')}
        </h1>
      </div>

      {imageUrl && (selectedItem || isBible) && !loading && (
        <div className="relative w-full h-[35vh] overflow-hidden shadow-2xl animate-in fade-in duration-1000">
           <img 
            src={imageUrl} 
            className="w-full h-full object-cover brightness-110 contrast-110 saturate-[1.2] transition-transform duration-[5s] hover:scale-110" 
            alt={selectedItem || bookName} 
           />
           <div className="absolute inset-0 bg-gradient-to-t from-white via-transparent to-black/20"></div>
           <div className="absolute bottom-0 left-0 right-0 h-1 bg-[#0ea5e9] opacity-50"></div>
        </div>
      )}

      <div className="px-7 pt-10">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-48 space-y-6">
            <div className="w-16 h-16 border-[5px] border-[#0ea5e9]/20 border-t-[#0ea5e9] rounded-full animate-spin"></div>
            <p className="text-[#0ea5e9] font-black uppercase text-sm tracking-[0.4em] animate-pulse">{t.loading}</p>
          </div>
        ) : selectedItem || isBible ? (
          <article className="animate-in fade-in slide-in-from-bottom-8 duration-1000 text-zinc-800 pb-20">
            <div className="prose prose-zinc max-w-none">
              {detailContent.split('\n').map((line, i) => {
                const trimmed = line.trim();
                if (!trimmed) return <div key={i} className="h-6" />;
                if (trimmed.startsWith('#')) {
                  return (
                    <h2 key={i} className="text-[#0ea5e9] font-serif-church font-black text-3xl mt-14 mb-8 border-l-[6px] border-[#0ea5e9] pl-6 uppercase tracking-tight leading-tight">
                      {trimmed.replace(/^#+\s*/, '')}
                    </h2>
                  );
                }
                return (
                  <p key={i} className="mb-8 leading-[1.8] font-serif-church text-xl opacity-90 first-letter:text-4xl first-letter:font-bold first-letter:text-[#0ea5e9] first-letter:mr-1">
                    {trimmed}
                  </p>
                );
              })}
            </div>

            <div className="mt-20 pt-10 border-t border-gray-100 text-center">
               <p className="underline decoration-[#0ea5e9]/30 underline-offset-8 decoration-2 italic text-zinc-400 font-serif-church text-lg">
                {TRANSLATIONS[language].aboutUnderline}
               </p>
            </div>
          </article>
        ) : (
          <div className="space-y-10">
            <div className="relative group">
              <MagnifyingGlassIcon className="w-6 h-6 absolute left-6 top-1/2 -translate-y-1/2 text-zinc-400 group-focus-within:text-[#0ea5e9] transition-colors" />
              <input 
                type="text" 
                placeholder={t.search} 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-16 pr-8 py-6 bg-white text-zinc-800 rounded-[2.5rem] border-2 border-gray-100 focus:border-[#0ea5e9]/20 outline-none font-bold shadow-xl transition-all placeholder:text-zinc-500 text-lg"
              />
            </div>

            <div className="grid grid-cols-1 gap-6">
              {filteredList.map((item, idx) => (
                <button 
                  key={idx} 
                  onClick={() => handleSelectItem(item.name)} 
                  className="w-full flex items-center justify-between p-8 bg-white rounded-[3rem] border border-gray-100 shadow-lg hover:shadow-2xl hover:-translate-y-1 transition-all active:scale-95 group text-left"
                >
                  <div className="flex-grow pr-6">
                    <span className="text-2xl font-black text-zinc-900 group-hover:text-[#0ea5e9] transition-colors leading-tight block mb-2">
                      {item.name}
                    </span>
                    <div className="flex items-center space-x-3 mb-3">
                       {item.year && (
                         <span className="px-3 py-1 bg-sky-100 text-[#0ea5e9] text-xs font-black rounded-full uppercase tracking-tighter">
                           {item.year}
                         </span>
                       )}
                       <span className="text-[10px] text-zinc-400 font-bold uppercase tracking-widest">{categoryId}</span>
                    </div>
                    <p className="text-sm text-zinc-500 font-medium leading-relaxed line-clamp-2">
                      {item.description}
                    </p>
                  </div>
                  <div className="bg-[#0ea5e9] p-4 rounded-full shadow-xl group-hover:scale-110 transition-transform group-hover:rotate-12">
                    <ChevronRightIcon className="w-6 h-6 text-white" />
                  </div>
                </button>
              ))}
            </div>

            {filteredList.length === 0 && (
              <div className="text-center py-32">
                <div className="w-24 h-24 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-6 opacity-50">
                   <MagnifyingGlassIcon className="w-10 h-10 text-zinc-300" />
                </div>
                <p className="text-zinc-500 font-black text-lg uppercase tracking-widest">{t.noResults}</p>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

