      <div className="p-6 space-y-8">
        {/* Category Tabs */}
        {!searchQuery && (
          <div className="flex space-x-3 overflow-x-auto no-scrollbar pb-3">
            {[
              { id: 'monasteries', label: t.monasteries },
              { id: 'abnet', label: t.abnet },
              { id: 'teachers', label: t.teachers },
              { id: 'holidays', label: t.holidays }
            ].map((cat) => (
              <button
                key={cat.id}
                onClick={() => setActiveTab(cat.id as any)}
                className={`flex-shrink-0 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] transition-all shadow-sm active:scale-95 ${
                  activeTab === cat.id 
                    ? 'bg-[#0ea5e9] text-white' 
                    : 'bg-white text-zinc-500 border border-gray-100'
                }`}
              >
                {cat.label}
              </button>
            ))}
          </div>
        )}

        <div className="grid grid-cols-1 gap-4 animate-in fade-in slide-in-from-bottom-5 duration-700">
          {filteredList.map((item, i) => (
            <button 
              key={i} 
              onClick={() => navigate(`/content/search?query=${encodeURIComponent(item.name)}`)} 
              className="w-full p-6 bg-white rounded-[2.5rem] shadow-sm border border-gray-100 flex items-center justify-between group transition-all active:scale-[0.98] hover:bg-gray-50"
            >
              <div className="flex items-center space-x-5">
                <div className="w-12 h-12 bg-sky-500/10 rounded-2xl flex items-center justify-center text-sky-600 font-black text-sm transition-all group-hover:bg-[#0ea5e9] group-hover:text-white shadow-inner">
                  {i + 1}
                </div>
                <div className="text-left">
                  <span className="text-base font-black text-black group-hover:text-[#0ea5e9] transition-colors tracking-tight leading-tight">
                    {item.name}
                  </span>
                  <p className="text-[10px] text-zinc-400 font-bold uppercase tracking-widest mt-1">
                    {item.info}
                  </p>
                </div>
              </div>
              <ChevronRightIcon className="w-5 h-5 text-[#0ea5e9] group-hover:translate-x-1 transition-transform" />
            </button>
