import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { UserIcon, MagnifyingGlassIcon, ArrowsUpDownIcon, HeartIcon as HeartOutline } from '@heroicons/react/24/outline';
import { HeartIcon as HeartSolid, ChevronLeftIcon as ChevronLeftSolid } from '@heroicons/react/24/solid';
import { Language } from '../types';
import { TRANSLATIONS } from '../constants';

const PrayerRequestPage: React.FC<{ language: Language }> = ({ language }) => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'ask' | 'pray'>('ask');
  const [name, setName] = useState('');
  const [request, setRequest] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [sortOrder, setSortOrder] = useState<'newest' | 'oldest'>('newest');
  const [submitted, setSubmitted] = useState(false);
  const [prayedSet, setPrayedSet] = useState<Set<string>>(new Set());

  const t = TRANSLATIONS[language];

  const mockRequests = [
    { id: '1', name: 'ወለተመስቀል', time: '38m ago', request: 'ስለሁሉ ነገር እግዚአብሔር ይመስገን', timestamp: Date.now() - 38 * 60 * 1000, count: 12 },
    { id: '2', name: 'ወልደሰንበት', time: '44m ago', request: 'እድሌ መንገዴ በረና መክፈቱ ሁሉ ተዘግቶብኛል።', timestamp: Date.now() - 44 * 60 * 1000, count: 5 },
    { id: '3', name: 'Martha', time: '1h ago', request: 'Please pray for my family health.', timestamp: Date.now() - 60 * 60 * 1000, count: 21 }
  ];

  const sortedAndFiltered = useMemo(() => {
    let res = mockRequests.filter(r => 
      r.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
      r.request.toLowerCase().includes(searchQuery.toLowerCase())
    );
    return res.sort((a, b) => sortOrder === 'newest' ? b.timestamp - a.timestamp : a.timestamp - b.timestamp);
  }, [searchQuery, sortOrder]);

  const togglePrayed = (id: string) => {
    const newSet = new Set(prayedSet);
    if (newSet.has(id)) {
      newSet.delete(id);
    } else {
      newSet.add(id);
    }
    setPrayedSet(newSet);
  };

  return (
    <div className="min-h-screen bg-white text-black pb-32 max-w-xl mx-auto transition-colors duration-300">
      {/* Sky Blue Header */}
      <div className="bg-[#0ea5e9] p-4 pt-6 flex flex-col items-center text-white relative shadow-md rounded-b-[2rem]">
        <button 
          onClick={() => navigate(-1)} 
          className="absolute left-4 top-6 p-2 hover:bg-white/20 rounded-full transition-colors"
        >
          <ChevronLeftSolid className="w-5 h-5" />
        </button>
        <h1 className="text-lg font-black tracking-tight mb-4 uppercase">{t.prayerRequest}</h1>
        <div className="flex w-full relative bg-black/10 rounded-xl p-1">
          <button 
            onClick={() => setActiveTab('ask')} 
            className={`flex-1 py-2 text-xs font-black transition-all rounded-lg ${activeTab === 'ask' ? 'bg-white text-sky-600 shadow-sm' : 'text-white/80'}`}
          >
            {t.ask}
          </button>
          <button 
            onClick={() => setActiveTab('pray')} 
            className={`flex-1 py-2 text-xs font-black transition-all rounded-lg ${activeTab === 'pray' ? 'bg-white text-sky-600 shadow-sm' : 'text-white/80'}`}
          >
            {t.pray}
          </button>
        </div>
      </div>

      <div className="p-4 pt-6">
        {activeTab === 'ask' ? (
          <form onSubmit={(e) => { e.preventDefault(); setSubmitted(true); setTimeout(() => navigate(-1), 1500); }} className="space-y-4">
            <div className="space-y-1.5">
              <label className="text-[10px] font-black uppercase tracking-widest text-zinc-400 ml-1">{t.name}</label>
              <input 
                type="text" 
                value={name} 
                onChange={(e) => setName(e.target.value)} 
                placeholder="Enter your name" 
                className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl text-sm font-bold outline-none focus:ring-2 focus:ring-sky-500/20 transition-all" 
                required 
              />
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black uppercase tracking-widest text-zinc-400 ml-1">{t.request}</label>
              <textarea 
                value={request} 
                onChange={(e) => setRequest(e.target.value)} 
                placeholder="How can we pray for you?" 
                className="w-full p-4 h-36 bg-gray-50 border border-gray-100 rounded-2xl text-sm font-bold outline-none focus:ring-2 focus:ring-sky-500/20 transition-all resize-none" 
                required 
              />
            </div>
            <button 
              type="submit" 
              disabled={submitted} 
              className="w-full py-4 rounded-2xl text-base font-black bg-[#0ea5e9] text-white shadow-xl shadow-sky-500/20 active:scale-[0.98] transition-all disabled:opacity-50 mt-4"
            >
              {submitted ? 'Submitting...' : t.submit}
            </button>
          </form>
        ) : (
          <div className="space-y-4">
            <div className="flex items-center space-x-2">
              <div className="relative flex-grow group">
                <MagnifyingGlassIcon className="w-4 h-4 absolute left-4 top-1/2 -translate-y-1/2 text-zinc-400 group-focus-within:text-[#0ea5e9] transition-colors" />
                <input 
                  type="text" 
                  placeholder="Search" 
                  value={searchQuery} 
                  onChange={(e) => setSearchQuery(e.target.value)} 
                  className="w-full pl-11 pr-4 py-3.5 bg-gray-50 text-black rounded-2xl border border-gray-100 text-xs font-black outline-none focus:ring-2 focus:ring-sky-500/20 transition-all" 
                />
              </div>
              <button 
                onClick={() => setSortOrder(sortOrder === 'newest' ? 'oldest' : 'newest')} 
                className="flex items-center px-4 py-3.5 bg-sky-50 border border-sky-100 rounded-2xl hover:bg-sky-100 transition-colors"
              >
                <ArrowsUpDownIcon className="w-4 h-4 text-sky-600 mr-2" />
                <span className="text-[10px] font-black text-sky-600 uppercase tracking-tight">
                  {sortOrder === 'newest' ? t.newest : t.oldest}
                </span>
              </button>
            </div>

            <div className="space-y-3">
              {sortedAndFiltered.map((item) => {
                const isPrayed = prayedSet.has(item.id);
                return (
                  <div key={item.id} className="bg-white rounded-[2rem] p-5 border border-gray-100 flex items-start space-x-4 shadow-sm hover:shadow-md transition-shadow group relative">
                    <div className="w-10 h-10 bg-gradient-to-br from-sky-400 to-sky-600 rounded-full flex items-center justify-center text-white flex-shrink-0 shadow-lg group-hover:scale-105 transition-transform">
                      <UserIcon className="w-5 h-5" />
                    </div>
                    <div className="flex-grow">
                      <div className="flex justify-between items-start mb-1">
                        <h4 className="text-sm font-black text-zinc-800">{item.name}</h4>
                        <span className="text-[10px] font-bold text-zinc-400">{item.time}</span>
                      </div>
                      <p className="text-xs text-zinc-600 leading-relaxed font-medium mb-4">
                        {item.request}
                      </p>
                      <button 
                        onClick={() => togglePrayed(item.id)}
                        className={`flex items-center space-x-2 px-4 py-2 rounded-full transition-all active:scale-95 ${
                          isPrayed 
                            ? 'bg-sky-500 text-white shadow-md' 
                            : 'bg-gray-100 text-zinc-500 hover:bg-gray-200'
                        }`}
                      >
                        {isPrayed ? (
                          <HeartSolid className="w-4 h-4 animate-pulse" />
                        ) : (
                          <HeartOutline className="w-4 h-4" />
                        )}
                        <span className="text-[10px] font-black uppercase tracking-wider">
                          {isPrayed ? 'Prayed For' : 'Pray'}
                        </span>
                        {isPrayed && (
                          <span className="text-[10px] font-bold ml-1 opacity-80">
                            ({item.count + 1})
                          </span>
                        )}
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default PrayerRequestPage;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ChevronLeftIcon, LinkIcon, CheckCircleIcon } from '@heroicons/react/24/solid';
import { Language } from '../types';

interface InviteFriendsProps {
  language: Language;
}

const InviteFriends: React.FC<InviteFriendsProps> = ({ language }) => {
  const navigate = useNavigate();
  const [copied, setCopied] = useState(false);

  const handleCopyLink = () => {
    const inviteLink = window.location.origin + "/#/invite";
    navigator.clipboard.writeText(inviteLink);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: 'መራሔ ጥበብ (Guide to Wisdom)',
          text: "Invite your friends to join you on መራሔ ጥበብ! Together, let's deepen our Orthodox Christian faith, embrace the blessings of prayers, and grow in wisdom and grace.",
          url: window.location.origin,
        });
      } catch (err) { console.log(err); }
    } else {
      handleCopyLink();
    }
  };

  return (
    <div className="max-w-xl mx-auto min-h-screen bg-white transition-colors duration-300">
      {/* Sky Blue Header */}
      <div className="bg-[#0ea5e9] pt-12 pb-10 rounded-b-[2.5rem] flex flex-col items-center relative shadow-xl">
        <button 
          onClick={() => navigate(-1)} 
          className="absolute left-6 top-14 p-1.5 hover:bg-white/20 rounded-full transition-colors text-white"
        >
          <ChevronLeftIcon className="w-6 h-6" />
        </button>
        <h1 className="text-3xl font-serif font-medium text-white tracking-wide">Invite Your Friends</h1>
      </div>

      <div className="px-6 py-10 flex flex-col items-center">
        {/* Icon Card with Sky Blue border accent */}
