import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, Modality } from "@google/genai";
import { Language } from '../types';
import { LANGUAGES, TRANSLATIONS } from '../constants';
import { 
  PlayCircleIcon, 
  PauseCircleIcon
} from '@heroicons/react/24/outline';
import { PlayIcon, PauseIcon, LanguageIcon, MicrophoneIcon } from '@heroicons/react/24/solid';

function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const AudioPage: React.FC<any> = ({ language, setLanguage }) => {
  const [activeTab, setActiveTab] = useState<'monasteries' | 'abnet' | 'teachers' | 'holidays'>('monasteries');
  const [playingItem, setPlayingItem] = useState<any>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isLoadingAudio, setIsLoadingAudio] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const t = TRANSLATIONS[language];

  const data = {
    monasteries: [
      { name: "Debre Damo (ደብረ ዳሞ)", info: "Founded by Abune Aregawi", prompt: "Read the history of Debre Damo monastery in Ethiopia." },
      { name: "Axum Tsion (አክሱም ጽዮን)", info: "The Ark of Covenant", prompt: "Read the history of Axum Tsion Church and the Ark of Covenant." },
      { name: "Debre Libanos (ደብረ ሊባኖስ)", info: "St. Tekle Haymanot", prompt: "Read the life and history of Debre Libanos monastery." },
      { name: "Waldiba (ዋልድባ)", info: "The Land of Monks", prompt: "Read the spiritual history of Waldiba monastery." },
    ],
    abnet: [
      { name: "Zema Bet (ዜማ ቤት)", info: "Liturgical Chant", prompt: "Read about Zema Bet church education and its importance." },
      { name: "Qine Bet (ቅኔ ቤት)", info: "Poetry & Logic", prompt: "Read about Qine Bet and its role in Ethiopian philosophy." },
      { name: "Nebab Bet (ንባብ ቤት)", info: "The First Level", prompt: "Read about Nebab Bet church education for beginners." },
    ],
    teachers: [
      { name: "Saint Yared (ቅዱስ ያሬድ)", info: "The Great Musician", prompt: "Read the biography of Saint Yared the father of music." },
      { name: "Tekle Haymanot (ተክለ ሃይማኖት)", info: "The Star of the East", prompt: "Read the life story of Abune Tekle Haymanot." },
    ],
    holidays: [
      { name: "Meskel (መስቀል)", info: "Finding the True Cross", prompt: "Read the history of the Meskel holiday in Ethiopia." },
      { name: "Timket (ጥምቀት)", info: "Epiphany", prompt: "Read the history and celebration of Timket in Ethiopia." },
    ]
  };

  const stopAudio = () => {
    if (sourceNodeRef.current) {
      sourceNodeRef.current.stop();
      sourceNodeRef.current = null;
    }
    setIsPlaying(false);
  };

  const playItem = async (item: any) => {
    if (playingItem?.name === item.name && isPlaying) {
      stopAudio();
      return;
    }

    setPlayingItem(item);
    setIsLoadingAudio(true);
    stopAudio();

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const promptText = `Read the following in a calm, spiritual voice in ${language}: ${item.prompt}. Provide a concise 200-word history.`;

      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: promptText }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Kore' },
            },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (!base64Audio) throw new Error("No audio data");

      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const audioData = decodeBase64(base64Audio);
      const audioBuffer = await decodeAudioData(audioData, audioContextRef.current, 24000, 1);

      const source = audioContextRef.current.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(audioContextRef.current.destination);
      source.onended = () => setIsPlaying(false);

      sourceNodeRef.current = source;
      source.start();
      setIsPlaying(true);
    } catch (error) {
      console.error("TTS Error:", error);
    } finally {
      setIsLoadingAudio(false);
    }
  };

  useEffect(() => {
    return () => stopAudio();
  }, []);

  return (
    <div className="max-w-xl mx-auto min-h-screen bg-white dark:bg-black transition-colors duration-300 pb-48">
      {/* Sky Blue Header Area */}
      <div className="bg-[#0ea5e9] p-6 pb-12 rounded-b-[3.5rem] shadow-2xl text-white relative">
        <div className="flex items-center justify-center space-x-3 mb-8">
           <MicrophoneIcon className="w-8 h-8" />
           <h1 className="text-3xl font-serif font-bold tracking-wide uppercase">{t.audio}</h1>
        </div>

        <div className="space-y-4">
          <div className="flex items-center justify-center space-x-2 opacity-80">
            <LanguageIcon className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">{t.changeLanguage}</span>
          </div>
          <div className="flex flex-wrap justify-center gap-2">
            {LANGUAGES.map((lang) => (
              <button
                key={lang.id}
                onClick={() => setLanguage(lang.id as Language)}
                className={`py-2 px-4 rounded-xl text-[10px] font-black transition-all border ${
                  language === lang.id 
                    ? 'bg-white text-[#0ea5e9] border-white shadow-lg scale-110' 
                    : 'bg-black/10 text-white border-white/20 hover:bg-black/20'
                }`}
              >
                {lang.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="p-6 space-y-6 -mt-6">
        <div className="flex space-x-2 overflow-x-auto no-scrollbar pb-2">
          {Object.keys(data).map((cat) => (
            <button
              key={cat}
              onClick={() => setActiveTab(cat as any)}
              className={`flex-shrink-0 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
                activeTab === cat 
                  ? 'bg-[#0ea5e9] text-white shadow-lg' 
                  : 'bg-gray-100 dark:bg-zinc-900 text-zinc-500 dark:text-zinc-400 border border-transparent dark:border-zinc-800'
              }`}
            >
              {t[cat] || cat}
            </button>
          ))}
        </div>

        <div className="grid grid-cols-1 gap-4 animate-in fade-in duration-500">
          {data[activeTab].map((item, idx) => (
            <button 
              key={idx}
              onClick={() => playItem(item)}
              className={`w-full flex items-center p-6 bg-white dark:bg-zinc-900 rounded-[2.5rem] border transition-all shadow-lg active:scale-95 ${
                playingItem?.name === item.name ? 'border-[#0ea5e9] ring-1 ring-[#0ea5e9]/30' : 'border-gray-100 dark:border-zinc-800'
              }`}
            >
              <div className="w-14 h-14 bg-[#0ea5e9]/10 rounded-2xl flex items-center justify-center text-sky-600 font-black text-lg mr-5">
                {idx + 1}
              </div>
              <div className="flex-grow text-left">
                <h3 className="text-lg font-black text-black dark:text-white leading-tight">{item.name}</h3>
                <p className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest mt-1">{item.info}</p>
              </div>
              <div className="text-[#0ea5e9]">
                {playingItem?.name === item.name && isPlaying ? (
                  <PauseCircleIcon className="w-12 h-12" />
                ) : (
                  <PlayCircleIcon className="w-12 h-12" />
                )}
              </div>
            </button>
          ))}
        </div>
      </div>

      {(playingItem || isLoadingAudio) && (
        <div className="fixed bottom-24 left-4 right-4 bg-white dark:bg-zinc-900 p-6 rounded-[2.5rem] shadow-[0_25px_60px_rgba(0,0,0,0.15)] border border-gray-100 dark:border-zinc-800 z-50 animate-in slide-in-from-bottom-8">
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-5 truncate">
              <div className="relative">
                <div className={`w-14 h-14 rounded-2xl bg-[#0ea5e9] flex items-center justify-center text-white shadow-lg ${isPlaying ? 'animate-pulse' : ''}`}>
                  <MicrophoneIcon className="w-7 h-7" />
                </div>
                {isLoadingAudio && (
                  <div className="absolute inset-0 flex items-center justify-center bg-black/40 rounded-2xl">
                    <div className="w-6 h-6 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                  </div>
                )}
              </div>
              <div className="truncate">
                <p className="font-black text-lg text-black dark:text-white truncate">
                  {playingItem?.name || t.loading}
                </p>
                <p className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">
                  {isLoadingAudio ? 'Generating AI Voice...' : isPlaying ? 'Now Reading...' : 'Paused'}
                </p>
              </div>
            </div>
            <button 
              onClick={() => playingItem && playItem(playingItem)} 
              disabled={isLoadingAudio}
              className="w-14 h-14 bg-[#0ea5e9] text-white rounded-full flex items-center justify-center shadow-xl active:scale-90 transition-all disabled:opacity-50"
            >
              {isPlaying ? <PauseIcon className="w-7 h-7" /> : <PlayIcon className="w-7 h-7 ml-1" />}
            </button>
          </div>
          <div className="mt-5 h-1.5 w-full bg-gray-100 dark:bg-zinc-800 rounded-full overflow-hidden">
             <div className={`h-full bg-[#0ea5e9] transition-all duration-300 ${isPlaying ? 'w-2/3' : 'w-0'}`}></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AudioPage;

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Home from './pages/Home';
import AudioPage from './pages/AudioPage';
import BiblePage from './pages/BiblePage';
import Community from './pages/Community';
import Settings from './pages/Settings';
import AboutUs from './pages/AboutUs';
import NotificationPage from './pages/NotificationPage';
import ContentDetail from './pages/ContentDetail';
import PrayerRequestPage from './pages/PrayerRequestPage';
import InviteFriends from './pages/InviteFriends';
import BottomNav from './components/BottomNav';
import { Language } from './types';

const App: React.FC = () => {
  const [language, setLanguage] = useState<Language>(() => {
    return (localStorage.getItem('appLanguage') as Language) || 'Amharic';
  });
  const [fontSize, setFontSize] = useState(() => {
    return parseInt(localStorage.getItem('appFontSize') || '18');
  });
  const [darkMode, setDarkMode] = useState(() => {
    const saved = localStorage.getItem('darkMode');
    if (saved !== null) return saved === 'true';
    return window.matchMedia('(prefers-color-scheme: dark)').matches;
  });

  useEffect(() => {
    localStorage.setItem('appLanguage', language);
  }, [language]);

  useEffect(() => {
    localStorage.setItem('appFontSize', fontSize.toString());
  }, [fontSize]);

  useEffect(() => {
    localStorage.setItem('darkMode', darkMode.toString());
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  return (
    <HashRouter>
      <div className={`main-container min-h-screen flex flex-col transition-colors duration-300 ${darkMode ? 'bg-black text-white' : 'bg-white text-black'}`}>
        <main className="flex-grow pb-24">
          <Routes>
            <Route path="/" element={<Home language={language} setLanguage={setLanguage} />} />
            <Route path="/audio" element={<AudioPage language={language} setLanguage={setLanguage} />} />
            <Route path="/bible" element={<BiblePage language={language} setLanguage={setLanguage} />} />
            <Route path="/community" element={<Community language={language} setLanguage={setLanguage} />} />
            <Route path="/prayer-request" element={<PrayerRequestPage language={language} />} />
            <Route path="/invite-friends" element={<InviteFriends language={language} />} />
            <Route path="/about-us" element={<AboutUs language={language} setLanguage={setLanguage} />} />
            <Route path="/notifications" element={<NotificationPage language={language} />} />
            <Route path="/settings" element={<Settings 
              language={language} 
              setLanguage={setLanguage} 
              fontSize={fontSize}
              setFontSize={setFontSize}
              darkMode={darkMode}
              setDarkMode={setDarkMode}
            />} />
            <Route path="/content/:categoryId" element={<ContentDetail language={language} fontSize={fontSize} />} />
            <Route path="/content/search" element={<ContentDetail language={language} fontSize={fontSize} />} />
            <Route path="/bible/:bookName" element={<ContentDetail language={language} fontSize={fontSize} isBible />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>
        <BottomNav language={language} />
      </div>
    </HashRouter>
  );
};

export default App;

