    } else {
      handleCopyLink();
    }
  };

  return (
    <div className="max-w-xl mx-auto min-h-screen bg-white dark:bg-black transition-colors duration-300">
      {/* Sky Blue Header */}
      <div className="bg-[#0ea5e9] pt-12 pb-10 rounded-b-[2.5rem] flex flex-col items-center relative shadow-xl">
