                onChange={(e) => setRequest(e.target.value)} 
                placeholder="How can we pray for you?" 
                className="w-full p-4 h-36 bg-gray-50 dark:bg-zinc-900 border border-gray-100 dark:border-zinc-800 rounded-2xl text-sm font-bold outline-none focus:ring-2 focus:ring-sky-500/20 transition-all resize-none text-black dark:text-zinc-100 placeholder:text-zinc-400 dark:placeholder:text-zinc-600" 
                required 
              />
            </div>
            <button 
              type="submit" 
              disabled={submitted} 
              className="w-full py-4 rounded-2xl text-base font-black bg-[#0ea5e9] text-white shadow-xl shadow-sky-500/20 active:scale-[0.98] transition-all disabled:opacity-50 mt-4"
            >
              {submitted ? 'Submitting...' : t.submit}
            </button>
          </form>
        ) : (
          <div className="space-y-4">
            <div className="flex items-center space-x-2">
              <div className="relative flex-grow group">
                <MagnifyingGlassIcon className="w-4 h-4 absolute left-4 top-1/2 -translate-y-1/2 text-zinc-400 dark:text-zinc-500 group-focus-within:text-[#0ea5e9] transition-colors" />
                <input 
                  type="text" 
                  placeholder="Search" 
                  value={searchQuery} 
                  onChange={(e) => setSearchQuery(e.target.value)} 
                  className="w-full pl-11 pr-4 py-3.5 bg-gray-50 dark:bg-zinc-900 text-black dark:text-zinc-100 rounded-2xl border border-gray-100 dark:border-zinc-800 text-xs font-black outline-none focus:ring-2 focus:ring-sky-500/20 transition-all" 
                />
              </div>
              <button 
                onClick={() => setSortOrder(sortOrder === 'newest' ? 'oldest' : 'newest')} 
                className="flex items-center px-4 py-3.5 bg-sky-50 dark:bg-sky-900/20 border border-sky-100 dark:border-sky-900/40 rounded-2xl hover:bg-sky-100 dark:hover:bg-sky-900/30 transition-colors"
              >
                <ArrowsUpDownIcon className="w-4 h-4 text-sky-600 dark:text-sky-400 mr-2" />
                <span className="text-[10px] font-black text-sky-600 dark:text-sky-400 uppercase tracking-tight">
                  {sortOrder === 'newest' ? t.newest : t.oldest}
                </span>
              </button>
            </div>

            <div className="space-y-3">
              {sortedAndFiltered.map((item) => {
                const isPrayed = prayedSet.has(item.id);
                return (
                  <div key={item.id} className="bg-white dark:bg-zinc-900 rounded-[2rem] p-5 border border-gray-100 dark:border-zinc-800 flex items-start space-x-4 shadow-sm hover:shadow-md transition-shadow group relative">
                    <div className="w-10 h-10 bg-gradient-to-br from-sky-400 to-sky-600 rounded-full flex items-center justify-center text-white flex-shrink-0 shadow-lg group-hover:scale-105 transition-transform">
                      <UserIcon className="w-5 h-5" />
                    </div>
                    <div className="flex-grow">
                      <div className="flex justify-between items-start mb-1">
                        <h4 className="text-sm font-black text-zinc-800 dark:text-zinc-100">{item.name}</h4>
                        <span className="text-[10px] font-bold text-zinc-400 dark:text-zinc-500">{item.time}</span>
                      </div>
                      <p className="text-xs text-zinc-600 dark:text-zinc-400 leading-relaxed font-medium mb-4">
                        {item.request}
                      </p>
                      <button 
                        onClick={() => togglePrayed(item.id)}
                        className={`flex items-center space-x-2 px-4 py-2 rounded-full transition-all active:scale-95 ${
                          isPrayed 
                            ? 'bg-sky-500 text-white shadow-md' 
                            : 'bg-gray-100 dark:bg-zinc-800 text-zinc-500 dark:text-zinc-400 hover:bg-gray-200 dark:hover:bg-zinc-700'
                        }`}
                      >
                        {isPrayed ? (
                          <HeartSolid className="w-4 h-4 animate-pulse" />
                        ) : (
                          <HeartOutline className="w-4 h-4" />
                        )}
                        <span className="text-[10px] font-black uppercase tracking-wider">
                          {isPrayed ? 'Prayed For' : 'Pray'}
                        </span>
                        {isPrayed && (
                          <span className="text-[10px] font-bold ml-1 opacity-80">
                            ({item.count + 1})
                          </span>
                        )}
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default PrayerRequestPage;

import React from 'react';
