import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, Modality } from "@google/genai";
import { Language } from '../types';
import { LANGUAGES, TRANSLATIONS } from '../constants';
import { 
  PlayCircleIcon, 
  PauseCircleIcon
} from '@heroicons/react/24/outline';
import { PlayIcon, PauseIcon, LanguageIcon, MicrophoneIcon } from '@heroicons/react/24/solid';

// Manual base64 decoding implementation as required by the coding guidelines
function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

// Custom audio decoding for raw PCM bytes returned by Gemini models
async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const AudioPage: React.FC<any> = ({ language, setLanguage }) => {
  const [activeTab, setActiveTab] = useState<'monasteries' | 'abnet' | 'teachers' | 'holidays'>('monasteries');
  const [playingItem, setPlayingItem] = useState<any>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isLoadingAudio, setIsLoadingAudio] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const t = TRANSLATIONS[language];

  const data = {
    monasteries: [
      { name: "Debre Damo (ደብረ ዳሞ)", info: "Founded by Abune Aregawi", prompt: "history of Debre Damo monastery in Ethiopia" },
      { name: "Axum Tsion (አክሱም ጽዮን)", info: "The Ark of Covenant", prompt: "history of Axum Tsion Church and the Ark of Covenant" },
      { name: "Debre Libanos (ደብረ ሊባኖስ)", info: "St. Tekle Haymanot", prompt: "life and history of Debre Libanos monastery" },
      { name: "Waldiba (ዋልድባ)", info: "The Land of Monks", prompt: "spiritual history of Waldiba monastery" },
    ],
    abnet: [
      { name: "Zema Bet (ዜማ ቤት)", info: "Liturgical Chant", prompt: "Zema Bet church education and its importance" },
      { name: "Qine Bet (ቅኔ ቤት)", info: "Poetry & Logic", prompt: "Qine Bet and its role in Ethiopian philosophy" },
      { name: "Nebab Bet (ንባብ ቤት)", info: "The First Level", prompt: "Nebab Bet church education for beginners" },
    ],
    teachers: [
      { name: "Saint Yared (ቅዱስ ያሬድ)", info: "The Great Musician", prompt: "biography of Saint Yared the father of music" },
      { name: "Tekle Haymanot (ተክለ ሃይማኖት)", info: "The Star of the East", prompt: "life story of Abune Tekle Haymanot" },
    ],
    holidays: [
      { name: "Meskel (መስቀል)", info: "Finding the True Cross", prompt: "history of the Meskel holiday in Ethiopia" },
      { name: "Timket (ጥምቀት)", info: "Epiphany", prompt: "history and celebration of Timket in Ethiopia" },
    ]
  };

  const stopAudio = () => {
    if (sourceNodeRef.current) {
      try {
        sourceNodeRef.current.stop();
      } catch (e) {}
      sourceNodeRef.current = null;
    }
    setIsPlaying(false);
  };

  const playItem = async (item: any) => {
    if (playingItem?.name === item.name && isPlaying) {
      stopAudio();
      return;
    }

    setPlayingItem(item);
    setIsLoadingAudio(true);
    setError(null);
    stopAudio();

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Step 1: Content Generation using a reasoning model
      const genPrompt = `Generate a concise 120-word historical profile of ${item.name} in ${language}. 
      Context: ${item.prompt}. 
      Tone: Spiritual, educational, and respectful. 
      Format: Text only.`;

      const genResult = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: genPrompt,
      });

      const textToSpeak = genResult.text;
      if (!textToSpeak) throw new Error("Could not generate text for speech.");

      // Step 2: Speech Synthesis using the dedicated TTS model
      const ttsResponse = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: textToSpeak }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Kore' },
            },
          },
        },
      });

      const base64Audio = ttsResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (!base64Audio) {
        throw new Error("Speech synthesis failed to return audio data.");
      }

      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const audioData = decodeBase64(base64Audio);
      const audioBuffer = await decodeAudioData(audioData, audioContextRef.current, 24000, 1);

      const source = audioContextRef.current.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(audioContextRef.current.destination);
      source.onended = () => setIsPlaying(false);

      sourceNodeRef.current = source;
      source.start();
      setIsPlaying(true);
    } catch (err: any) {
      console.error("Audio Processing Error:", err);
      setError(err.message || "Failed to process audio. Please try again.");
      setPlayingItem(null);
    } finally {
      setIsLoadingAudio(false);
    }
  };

  useEffect(() => {
    return () => stopAudio();
  }, []);

  return (
    <div className="max-w-xl mx-auto min-h-screen bg-white dark:bg-black transition-colors duration-300 pb-48">
      {/* Header */}
      <div className="bg-[#0ea5e9] p-6 pb-12 rounded-b-[3.5rem] shadow-2xl text-white relative">
        <div className="flex items-center justify-center space-x-3 mb-8">
           <MicrophoneIcon className="w-8 h-8" />
           <h1 className="text-3xl font-serif font-bold tracking-wide uppercase">{t.audio}</h1>
        </div>

        <div className="space-y-4">
          <div className="flex items-center justify-center space-x-2 opacity-80">
            <LanguageIcon className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">{t.changeLanguage}</span>
          </div>
          <div className="flex flex-wrap justify-center gap-2">
            {LANGUAGES.map((lang) => (
              <button
                key={lang.id}
                onClick={() => setLanguage(lang.id as Language)}
                className={`py-2 px-4 rounded-xl text-[10px] font-black transition-all border ${
                  language === lang.id 
                    ? 'bg-white text-[#0ea5e9] border-white shadow-lg scale-110' 
                    : 'bg-black/10 text-white border-white/20 hover:bg-black/20'
                }`}
              >
                {lang.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="p-6 space-y-6 -mt-6">
        {error && (
          <div className="bg-red-50 dark:bg-red-950/30 border border-red-200 dark:border-red-900 text-red-600 dark:text-red-400 p-4 rounded-2xl text-sm font-bold shadow-md">
            {error}
          </div>
        )}

        <div className="flex space-x-2 overflow-x-auto no-scrollbar pb-2">
          {Object.keys(data).map((cat) => (
            <button
              key={cat}
              onClick={() => setActiveTab(cat as any)}
              className={`flex-shrink-0 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
                activeTab === cat 
                  ? 'bg-[#0ea5e9] text-white shadow-lg' 
                  : 'bg-gray-100 dark:bg-zinc-900 text-zinc-500 dark:text-zinc-400 border border-transparent dark:border-zinc-800'
              }`}
            >
              {t[cat] || cat}
            </button>
          ))}
        </div>

        <div className="grid grid-cols-1 gap-4">
          {data[activeTab].map((item: any, idx: number) => (
            <button
              key={idx}
              onClick={() => playItem(item)}
              className="w-full flex items-center justify-between p-6 bg-white dark:bg-zinc-900 rounded-[2rem] border border-gray-100 dark:border-zinc-800 shadow-sm hover:shadow-md transition-all active:scale-[0.98] group"
            >
              <div className="flex items-center space-x-4">
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-colors ${
                  playingItem?.name === item.name && isPlaying 
                    ? 'bg-[#0ea5e9] text-white' 
                    : 'bg-sky-50 dark:bg-sky-900/20 text-[#0ea5e9]'
                }`}>
                  {playingItem?.name === item.name && isLoadingAudio ? (
                    <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                  ) : playingItem?.name === item.name && isPlaying ? (
                    <PauseIcon className="w-6 h-6" />
                  ) : (
                    <PlayIcon className="w-6 h-6" />
                  )}
                </div>
                <div className="text-left">
                  <h3 className="text-base font-black text-zinc-900 dark:text-zinc-100 group-hover:text-[#0ea5e9] transition-colors">{item.name}</h3>
                  <p className="text-[10px] text-zinc-400 dark:text-zinc-500 font-bold uppercase tracking-widest">{item.info}</p>
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>
    </div>
  );
};

export default AudioPage;

