    setIsLoadingAudio(true);
    setError(null);
    stopAudio();

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const genPrompt = `Generate a long, comprehensive, and immersive narration (about 400 words) of the history of ${item.name} in ${language}. 
