        )}

        {/* List of Histories */}
        <div className="grid grid-cols-1 gap-4">
          {data[activeTab].map((item: any, idx: number) => (
            <button
              key={idx}
              disabled={isLoading}
              onClick={() => generateAudio(item)}
              className={`w-full flex items-center justify-between p-7 rounded-[2.5rem] border transition-all active:scale-[0.98] group ${
                playingItem?.name === item.name 
                  ? 'bg-sky-50 dark:bg-sky-900/20 border-sky-200 dark:border-sky-800' 
                  : 'bg-white dark:bg-zinc-900 border-gray-100 dark:border-zinc-800 shadow-sm'
              }`}
            >
              <div className="flex items-center space-x-5">
                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center transition-all ${
                  playingItem?.name === item.name 
                    ? 'bg-[#0ea5e9] text-white' 
                    : 'bg-gray-100 dark:bg-zinc-800 text-zinc-400'
                }`}>
                  {playingItem?.name === item.name && isLoading ? (
                    <ArrowPathIcon className="w-7 h-7 animate-spin" />
                  ) : playingItem?.name === item.name && isPlaying ? (
                    <PauseIcon className="w-7 h-7" />
                  ) : (
                    <PlayIcon className="w-7 h-7" />
                  )}
                </div>
                <div className="text-left">
                  <h3 className="text-lg font-black text-zinc-900 dark:text-zinc-100">{item.name}</h3>
                  <p className="text-[10px] text-zinc-400 dark:text-zinc-500 font-bold uppercase tracking-widest">{item.info}</p>
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>

      {/* Persistent Audio Player Overlay */}
      {(playingItem || isLoading) && (
        <div className="fixed bottom-24 left-4 right-4 z-[60] animate-in slide-in-from-bottom-10 duration-500">
          <div className="max-w-xl mx-auto bg-white dark:bg-zinc-900 rounded-[2.5rem] shadow-2xl border border-gray-100 dark:border-zinc-800 p-6">
             <div className="flex items-center justify-between mb-4">
                <div className="flex items-center space-x-3">
                   <div className="w-12 h-12 bg-[#0ea5e9] rounded-2xl flex items-center justify-center text-white shadow-lg">
                      {isLoading ? <ArrowPathIcon className="w-6 h-6 animate-spin" /> : <MicrophoneIcon className="w-6 h-6" />}
                   </div>
                   <div className="overflow-hidden">
                      <h4 className="text-sm font-black text-zinc-900 dark:text-zinc-100 truncate w-40">{playingItem?.name || 'Preparing...'}</h4>
                      <p className="text-[10px] text-zinc-400 dark:text-zinc-500 font-black uppercase tracking-widest">{t[activeTab]}</p>
                   </div>
                </div>

                <div className="flex items-center space-x-2">
                   <button 
                    onClick={changeSpeed}
                    className="px-3 py-1.5 bg-gray-100 dark:bg-zinc-800 rounded-xl text-[10px] font-black text-[#0ea5e9]"
                   >
                     {playbackRate}x
                   </button>
                   {audioUrl && (
                     <button onClick={downloadAudio} className="p-2 text-zinc-400 hover:text-[#0ea5e9] transition-colors">
                        <ArrowDownTrayIcon className="w-5 h-5" />
                     </button>
                   )}
                   <button onClick={() => { setPlayingItem(null); setAudioUrl(null); }} className="p-2 text-zinc-400">
                      <XMarkIcon className="w-5 h-5" />
                   </button>
                </div>
             </div>

             {/* Progress Bar & Seek */}
             <div className="space-y-1">
                <input 
                  type="range" 
                  min="0" 
                  max={duration || 100} 
                  value={currentTime}
                  onChange={handleSeek}
                  className="w-full h-1.5 bg-gray-200 dark:bg-zinc-800 rounded-lg appearance-none cursor-pointer accent-[#0ea5e9]"
                />
                <div className="flex justify-between text-[10px] font-bold text-zinc-400 dark:text-zinc-600">
                   <span>{formatTime(currentTime)}</span>
                   <span>{formatTime(duration)}</span>
                </div>
             </div>

             {/* Playback Controls */}
             <div className="flex items-center justify-center space-x-10 mt-2">
                <button onClick={() => audioRef.current && (audioRef.current.currentTime -= 10)} className="text-zinc-300 hover:text-zinc-500 transition-colors">
                   <BackwardIcon className="w-8 h-8" />
                </button>
                <button 
                  onClick={togglePlay} 
                  disabled={isLoading}
                  className="w-16 h-16 bg-[#0ea5e9] rounded-full flex items-center justify-center text-white shadow-xl active:scale-90 transition-transform disabled:opacity-50"
                >
                   {isPlaying ? <PauseIcon className="w-8 h-8" /> : <PlayIcon className="w-8 h-8 ml-1" />}
                </button>
                <button onClick={() => audioRef.current && (audioRef.current.currentTime += 10)} className="text-zinc-300 hover:text-zinc-500 transition-colors">
                   <ForwardIcon className="w-8 h-8" />
                </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AudioPage;

import React, { useState, useEffect, useMemo } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { ChevronLeftIcon, MagnifyingGlassIcon, ChevronRightIcon } from '@heroicons/react/24/solid';
import { GoogleGenAI, Type } from '@google/genai';
import { Language } from '../types';
import { TRANSLATIONS } from '../constants';

interface ContentDetailProps {
  language: Language;
  fontSize: number;
  isBible?: boolean;
}

const ContentDetail: React.FC<ContentDetailProps> = ({ language, fontSize, isBible }) => {
  const { categoryId, bookName } = useParams<{ categoryId?: string; bookName?: string }>();
  const navigate = useNavigate();
  const location = useLocation();
  const t = TRANSLATIONS[language];

  const [list, setList] = useState<any[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedItem, setSelectedItem] = useState<string | null>(null);
  const [detailContent, setDetailContent] = useState<string>('');
  const [imageUrl, setImageUrl] = useState<string>('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const queryParam = params.get('query');

    if (queryParam) {
      handleSelectItem(queryParam);
    } else if (isBible) {
      fetchBibleDetail();
    } else {
      fetchCategoryList();
    }
  }, [categoryId, bookName, language, isBible, location.search]);

  const fetchBibleDetail = async () => {
    setLoading(true);
    try {
      const genService = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const promptText = `Provide an exhaustive, long-form theological and historical overview of the Bible book "${bookName}" in ${language}. 
      Include:
      1. Extensive historical context of its writing and its unique place in the Ethiopic Canon.
      2. Major theological themes in great detail.
      3. Its specific liturgical usage in the Ethiopian Orthodox Tewahedo Church.
      4. Details about its translation into Ge'ez during the Aksumite period.
      Write at least 6-8 detailed paragraphs.`;
      const response = await genService.models.generateContent({ model: 'gemini-3-flash-preview', contents: promptText });
      setDetailContent(response.text || '');
      setImageUrl(`https://images.unsplash.com/photo-1507434965515-61970f2bd7c6?q=80&w=1200&auto=format&fit=crop`);
    } catch (e) { console.error(e); } finally { setLoading(false); }
  };

  const fetchCategoryList = async () => {
    if (!categoryId || categoryId === 'search') return;
    setLoading(true);
    try {
      const genService = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const promptText = `Provide a list of 20 major entries for "${categoryId}" (Monasteries, Teachers, Holidays, or Church Education) in the Ethiopian Orthodox Church tradition.
      Include founding dates, specific regions, and a short 'teaser' of their unique history.
      Return as JSON: [{"name": "...", "description": "...", "year": "...", "searchTerms": "..."}] in ${language}. 
      The 'searchTerms' should be English keywords for a VIVID, REAL photo.`;

      const response = await genService.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: promptText,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                year: { type: Type.STRING },
                searchTerms: { type: Type.STRING }
              },
              required: ["name", "description", "searchTerms"]
            }
          }
        }
      });
      setList(JSON.parse(response.text || '[]'));
    } catch (e) { console.error(e); } finally { setLoading(false); }
  };

  const handleSelectItem = async (itemName: string) => {
    setSelectedItem(itemName);
    setLoading(true);
    try {
      const genService = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const promptText = `Write an EXTREMELY DETAILED, LONG history of "${itemName}" for the Ethiopian Orthodox Church in ${language}. 
      Target length: 1000-1500 words. 
      - Use scholarly, spiritual, and descriptive language.
      - For Monasteries: Covering founding by specific saints, architectural secrets, royal connections, spiritual roles, and modern status.
      - For Teachers: A full life chronicle from birth, spiritual calling, miracles, major teachings, and impact on future generations.
      - For Holidays: Scriptural roots, historical introduction to Ethiopia, detailed liturgical rites, and social significance.
      - For Abnet: The specific curriculum, the daily life of a student, the mastery required, and its transmission through centuries.
      Use Markdown headers for each major section. At the end, add 'IMAGE_TAGS: [3 descriptive English keywords]'.`;

      const response = await genService.models.generateContent({ model: 'gemini-3-flash-preview', contents: promptText });
      const text = response.text || '';

      const tagsMatch = text.match(/IMAGE_TAGS:\s*(.*)/i);
      const cleanContent = text.replace(/IMAGE_TAGS:\s*(.*)/i, '').trim();
      setDetailContent(cleanContent);

      let keywords = tagsMatch ? tagsMatch[1] : itemName;
      setImageUrl(`https://loremflickr.com/1200/800/${encodeURIComponent(keywords)}/all`);
    } catch (e) { console.error(e); } finally { setLoading(false); }
  };

  const filteredList = useMemo(() => {
    if (!searchQuery.trim()) return list;
    return list.filter(item => item.name.toLowerCase().includes(searchQuery.toLowerCase()));
  }, [list, searchQuery]);

  return (
    <div className="max-w-xl mx-auto min-h-screen bg-white dark:bg-black transition-colors duration-300 pb-32 shadow-2xl">
      <div className="sticky top-0 bg-[#0ea5e9] text-white px-6 py-10 flex items-center shadow-xl z-50 rounded-b-[2.5rem]">
        <button 
          onClick={() => selectedItem ? setSelectedItem(null) : navigate(-1)} 
          className="mr-5 p-2.5 hover:bg-white/20 rounded-full transition-colors active:scale-90"
        >
          <ChevronLeftIcon className="w-6 h-6" />
        </button>
        <h1 className="text-2xl font-black truncate tracking-tight uppercase leading-none">
          {selectedItem || bookName || (categoryId ? t[categoryId] : 'History')}
        </h1>
      </div>

      {imageUrl && (selectedItem || isBible) && !loading && (
        <div className="relative w-full h-[40vh] overflow-hidden shadow-2xl animate-in fade-in duration-1000">
           <img src={imageUrl} className="w-full h-full object-cover brightness-90 saturate-[1.2]" alt={selectedItem || bookName} />
           <div className={`absolute inset-0 bg-gradient-to-t from-black/60 to-transparent`}></div>
           <div className="absolute bottom-6 left-8 right-8 text-white">
              <h2 className="text-3xl font-black uppercase tracking-tighter drop-shadow-lg">{selectedItem || bookName}</h2>
           </div>
        </div>
      )}

      <div className="px-7 pt-10">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-48 space-y-6">
            <div className="w-16 h-16 border-[5px] border-[#0ea5e9]/20 border-t-[#0ea5e9] rounded-full animate-spin"></div>
            <p className="text-[#0ea5e9] font-black uppercase text-sm tracking-[0.4em] animate-pulse">{t.loading}</p>
          </div>
        ) : selectedItem || isBible ? (
          <article className="animate-in fade-in slide-in-from-bottom-8 duration-1000 text-zinc-800 dark:text-zinc-200 pb-20">
            <div className="prose prose-zinc dark:prose-invert max-w-none" style={{ fontSize: `${fontSize}px` }}>
              {detailContent.split('\n').map((line, i) => {
                const trimmed = line.trim();
                if (!trimmed) return <div key={i} className="h-4" />;
                if (trimmed.startsWith('#')) {
                  return (
                    <h2 key={i} className="text-[#0ea5e9] font-serif-church font-black text-2xl mt-10 mb-4 uppercase tracking-tight">
                      {trimmed.replace(/^#+\s*/, '')}
                    </h2>
                  );
                }
                return (
                  <p key={i} className="mb-6 leading-[1.8] font-serif-church opacity-95 text-justify">
                    {trimmed}
                  </p>
                );
              })}
            </div>

            <div className="mt-20 pt-10 border-t border-gray-100 dark:border-zinc-800 text-center">
               <p className="underline decoration-[#0ea5e9]/30 underline-offset-8 decoration-2 italic text-zinc-400 dark:text-zinc-500 font-serif-church text-lg">
                {TRANSLATIONS[language].aboutUnderline}
               </p>
            </div>
          </article>
        ) : (
          <div className="space-y-8">
            <div className="relative group">
              <MagnifyingGlassIcon className="w-6 h-6 absolute left-6 top-1/2 -translate-y-1/2 text-zinc-400 group-focus-within:text-[#0ea5e9] transition-colors" />
              <input 
                type="text" 
                placeholder={t.search} 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-16 pr-8 py-5 bg-white dark:bg-zinc-900 text-zinc-800 dark:text-zinc-200 rounded-[2rem] border-2 border-gray-100 dark:border-zinc-800 focus:border-[#0ea5e9]/20 outline-none font-bold shadow-xl transition-all"
              />
            </div>

            <div className="grid grid-cols-1 gap-5">
              {filteredList.map((item, idx) => (
                <button 
                  key={idx} 
                  onClick={() => handleSelectItem(item.name)} 
                  className="w-full flex items-center justify-between p-7 bg-white dark:bg-zinc-900 rounded-[2.5rem] border border-gray-100 dark:border-zinc-800 shadow-lg hover:shadow-2xl transition-all group text-left"
                >
                  <div className="flex-grow pr-4">
                    <span className="text-xl font-black text-zinc-900 dark:text-white group-hover:text-[#0ea5e9] transition-colors block mb-2">
                      {item.name}
                    </span>
                    <p className="text-xs text-zinc-500 dark:text-zinc-400 font-medium leading-relaxed line-clamp-2">
                      {item.description}
                    </p>
                  </div>
                  <ChevronRightIcon className="w-6 h-6 text-[#0ea5e9] group-hover:translate-x-1 transition-transform" />
                </button>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default ContentDetail;

