            </button>
          ))}

          {filteredList.length === 0 && (
            <div className="text-center py-24 opacity-50">
              <MagnifyingGlassIcon className="w-16 h-16 mx-auto mb-4 text-zinc-300 dark:text-zinc-700" />
              <p className="text-zinc-500 dark:text-zinc-600 font-black text-sm uppercase tracking-widest">{t.noResults}</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

