  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const t = TRANSLATIONS[language];

  const data = {
    monasteries: [
      { name: "Debre Damo (ደብረ ዳሞ)", info: "Founded by Abune Aregawi", prompt: "Spiritual history of Debre Damo monastery, the rope climb, and its Aksumite origins." },
      { name: "Axum Tsion (አክሱም ጽዮን)", info: "The Ark of Covenant", prompt: "Comprehensive history of Aksum Tsion and the Ark of the Covenant." },
      { name: "Debre Libanos (ደብረ ሊባኖስ)", info: "St. Tekle Haymanot", prompt: "Life of Tekle Haymanot and the founding of the Shewan spiritual center." },
      { name: "Waldiba (ዋልድባ)", info: "The Land of Monks", prompt: "Immersive spiritual description of Waldiba and its role in Ethiopian monasticism." },
      { name: "Debre Bizen (ደብረ ቢዘን)", info: "Mount of Bizen", prompt: "History of Abune Filipos and the mountain-top spiritual fortress." }
    ],
    abnet: [
      { name: "Zema Bet (ዜማ ቤት)", info: "Liturgical Chant", prompt: "The training of Saint Yared's music. Explain Ge'ez, Ezel, and Araray modes." },
      { name: "Qine Bet (ቅኔ ቤት)", info: "Poetry & Logic", prompt: "The artistic depths of Ge'ez poetry and the 'Wax and Gold' philosophy." },
      { name: "Metsehaf Bet (መጽሐፍ ቤት)", info: "Interpretation", prompt: "The path of interpreting the Bible in the Tewahedo tradition." },
      { name: "Aquaquam (አቋቋም)", info: "Liturgical Dance", prompt: "The symbolic movements, the use of the prayer staff, and the sistrum." }
    ],
    teachers: [
      { name: "Saint Yared (ቅዱስ ያሬድ)", info: "The Father of Music", prompt: "Exhaustive biography of Saint Yared and the origin of divine music." },
      { name: "Tekle Haymanot (ተክለ ሃይማኖት)", info: "The Great Light", prompt: "Full life history, miracles, and legacy of Abune Tekle Haymanot." }
    ],
    holidays: [
      { name: "Meskel (መስቀል)", info: "True Cross", prompt: "The history of Queen Helena and the discovery of the True Cross." },
      { name: "Timket (ጥምቀት)", info: "Epiphany", prompt: "Scriptural meaning of Timket and the blessing of the waters." },
      { name: "Genna (ገና)", info: "Nativity", prompt: "Birth of Christ as celebrated in the Ethiopian tradition." }
    ]
  };

  const handleAudioTimeUpdate = () => {
    if (audioRef.current) {
      setCurrentTime(audioRef.current.currentTime);
      setDuration(audioRef.current.duration);
    }
  };

  const togglePlay = () => {
    if (audioRef.current) {
      if (isPlaying) {
        audioRef.current.pause();
      } else {
        audioRef.current.play().catch(console.error);
      }
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    if (audioRef.current) {
      audioRef.current.currentTime = time;
      setCurrentTime(time);
    }
  };

  const changeSpeed = () => {
    const speeds = [0.75, 1, 1.25, 1.5];
    const nextIndex = (speeds.indexOf(playbackRate) + 1) % speeds.length;
    const newSpeed = speeds[nextIndex];
    setPlaybackRate(newSpeed);
    if (audioRef.current) {
      audioRef.current.playbackRate = newSpeed;
    }
  };

  const downloadAudio = async () => {
    if (audioUrl) {
      setIsDownloading(true);
      // Simulate download preparation/progress
      await new Promise(r => setTimeout(r, 1000));
      const link = document.createElement('a');
      link.href = audioUrl;
      link.download = `${playingItem?.name || 'History'}.wav`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      setIsDownloading(false);
    }
  };

  const generateAudio = async (item: any) => {
    setPlayingItem(item);
    setIsLoading(true);
    setError(null);
    setAudioUrl(null);
    setIsPlaying(false);

    try {
      const GenerativeService = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const genPrompt = `Generate a comprehensive and immersive narration (approx 600 words) of the history of ${item.name} in ${language}. 
      Context: ${item.prompt}. 
      Tone: Deeply spiritual, respectful, and educational.`;

      const genResult = await GenerativeService.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: genPrompt,
      });

      const textToSpeak = genResult.text;
      if (!textToSpeak) throw new Error("Could not prepare the narration text.");

      const ttsResponse = await GenerativeService.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: textToSpeak }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Kore' }, 
            },
          },
        },
      });

      const base64Audio = ttsResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (!base64Audio) throw new Error("The narration service is currently unavailable.");

      const rawData = decodeBase64(base64Audio);
      const int16Data = new Int16Array(rawData.buffer);
      const wavBlob = pcmToWav(int16Data, 24000);
      const url = URL.createObjectURL(wavBlob);

      setAudioUrl(url);

      if ('mediaSession' in navigator) {
        navigator.mediaSession.metadata = new MediaMetadata({
          title: item.name,
          artist: 'መራሔ ጥበብ',
          album: t[activeTab],
          artwork: [{ src: 'https://i.ibb.co/3mS6qfN/merahe-icon.jpg', sizes: '512x512', type: 'image/jpeg' }]
        });

        navigator.mediaSession.setActionHandler('play', () => audioRef.current?.play());
        navigator.mediaSession.setActionHandler('pause', () => audioRef.current?.pause());
        navigator.mediaSession.setActionHandler('seekbackward', () => { if(audioRef.current) audioRef.current.currentTime -= 10; });
        navigator.mediaSession.setActionHandler('seekforward', () => { if(audioRef.current) audioRef.current.currentTime += 10; });
      }

    } catch (err: any) {
      setError({ 
        message: "Unable to start the history audio.", 
        details: "Please check your internet connection and try again, or contact support if the issue persists." 
      });
    } finally {
      setIsLoading(false);
    }
  };

  const formatTime = (time: number) => {
    const mins = Math.floor(time / 60);
    const secs = Math.floor(time % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="max-w-xl mx-auto min-h-screen bg-white dark:bg-black transition-colors duration-300 pb-72">
      {audioUrl && (
        <audio 
          ref={audioRef} 
          src={audioUrl} 
          onTimeUpdate={handleAudioTimeUpdate} 
          onEnded={() => setIsPlaying(false)}
          onPlay={() => setIsPlaying(true)}
          onPause={() => setIsPlaying(false)}
        />
      )}

      <div className="bg-[#0ea5e9] p-6 pb-12 rounded-b-[3.5rem] shadow-2xl text-white relative">
        <div className="flex items-center justify-center space-x-3 mb-8">
           <MicrophoneIcon className="w-8 h-8" />
           <h1 className="text-3xl font-serif font-bold tracking-wide uppercase">{t.audio}</h1>
        </div>

        <div className="flex flex-wrap justify-center gap-2">
          {LANGUAGES.map((lang) => (
            <button
              key={lang.id}
              onClick={() => setLanguage(lang.id as Language)}
              className={`py-2 px-4 rounded-xl text-[10px] font-black transition-all border ${
                language === lang.id ? 'bg-white text-[#0ea5e9] scale-105' : 'bg-black/10 text-white'
              }`}
            >
              {lang.label}
            </button>
          ))}
        </div>
      </div>

      <div className="p-6 space-y-6 -mt-6">
        <div className="flex space-x-2 overflow-x-auto no-scrollbar pb-2">
          {Object.keys(data).map((cat) => (
            <button
              key={cat}
              onClick={() => setActiveTab(cat as any)}
              className={`flex-shrink-0 px-6 py-3 rounded-2xl text-[10px] font-black uppercase transition-all shadow-sm ${
                activeTab === cat ? 'bg-[#0ea5e9] text-white shadow-lg' : 'bg-gray-100 dark:bg-zinc-900 text-zinc-500'
              }`}
            >
              {t[cat] || cat}
            </button>
          ))}
        </div>

        {error && (
          <div className="bg-red-50 dark:bg-zinc-950 border-2 border-red-100 dark:border-red-900/40 p-6 rounded-[2rem] flex flex-col items-center text-center animate-in zoom-in-95">
             <div className="w-12 h-12 bg-red-100 dark:bg-red-900/30 rounded-full flex items-center justify-center mb-4">
                <ExclamationCircleIcon className="w-6 h-6 text-red-600 dark:text-red-400" />
             </div>
             <p className="text-red-800 dark:text-red-200 font-bold mb-1">{error.message}</p>
             <p className="text-xs text-red-600 dark:text-red-400/80 mb-5">{error.details}</p>
             <button 
                onClick={() => playingItem && generateAudio(playingItem)}
                className="flex items-center space-x-2 bg-red-600 text-white px-8 py-3 rounded-full font-black text-xs uppercase shadow-xl active:scale-95 transition-transform"
             >
                <ArrowPathIcon className="w-4 h-4" />
                <span>Try Again</span>
             </button>
          </div>
        )}

        <div className="grid grid-cols-1 gap-4">
          {data[activeTab].map((item: any, idx: number) => (
            <button
              key={idx}
              disabled={isLoading}
              onClick={() => generateAudio(item)}
              className={`w-full flex items-center justify-between p-7 rounded-[2.5rem] border transition-all active:scale-[0.98] group ${
                playingItem?.name === item.name 
                  ? 'bg-sky-50 dark:bg-sky-950/40 border-sky-200 dark:border-sky-800' 
                  : 'bg-white dark:bg-zinc-900 border-gray-100 dark:border-zinc-800 shadow-sm'
              }`}
            >
              <div className="flex items-center space-x-5">
                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center transition-all ${
                  playingItem?.name === item.name 
                    ? 'bg-[#0ea5e9] text-white shadow-lg shadow-sky-500/30' 
                    : 'bg-gray-100 dark:bg-zinc-800 text-zinc-400'
                }`}>
                  {playingItem?.name === item.name && isLoading ? (
                    <ArrowPathIcon className="w-7 h-7 animate-spin" />
                  ) : playingItem?.name === item.name && isPlaying ? (
                    <PauseIcon className="w-7 h-7" />
                  ) : (
                    <PlayIcon className="w-7 h-7" />
                  )}
                </div>
                <div className="text-left">
                  <h3 className="text-lg font-black text-zinc-900 dark:text-zinc-100">{item.name}</h3>
                  <p className="text-[10px] text-zinc-400 dark:text-zinc-500 font-bold uppercase tracking-widest leading-none mt-1">{item.info}</p>
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>

      {(playingItem || isLoading) && (
        <div className="fixed bottom-24 left-4 right-4 z-[60] animate-in slide-in-from-bottom-10 duration-500">
          <div className="max-w-xl mx-auto bg-white dark:bg-zinc-900 rounded-[2.5rem] shadow-[0_20px_50px_-12px_rgba(0,0,0,0.5)] border border-gray-100 dark:border-zinc-800 p-6">
             <div className="flex items-center justify-between mb-4">
                <div className="flex items-center space-x-3">
                   <div className="w-12 h-12 bg-[#0ea5e9] rounded-2xl flex items-center justify-center text-white shadow-lg">
                      {isLoading ? <ArrowPathIcon className="w-6 h-6 animate-spin" /> : <MicrophoneIcon className="w-6 h-6" />}
                   </div>
                   <div className="overflow-hidden">
                      <h4 className="text-sm font-black text-zinc-900 dark:text-zinc-100 truncate w-32">{playingItem?.name || 'Loading history...'}</h4>
                      <p className="text-[10px] text-[#0ea5e9] font-black uppercase tracking-widest">{t[activeTab]}</p>
                   </div>
                </div>

                <div className="flex items-center space-x-1">
                   <button 
                    onClick={changeSpeed}
                    className="px-3 py-1.5 bg-sky-50 dark:bg-sky-950 rounded-xl text-[10px] font-black text-[#0ea5e9] shadow-sm border border-sky-100 dark:border-sky-900/50"
                   >
                     {playbackRate}x
                   </button>
                   {audioUrl && (
                     <button 
                      onClick={downloadAudio} 
                      disabled={isDownloading}
                      className="p-2.5 text-zinc-400 hover:text-[#0ea5e9] transition-colors relative"
                     >
                        {isDownloading ? <ArrowPathIcon className="w-5 h-5 animate-spin" /> : <ArrowDownTrayIcon className="w-5 h-5" />}
                     </button>
                   )}
                   <button 
                    onClick={() => { setPlayingItem(null); setAudioUrl(null); }} 
                    className="p-2.5 text-zinc-400 hover:text-zinc-600 dark:hover:text-zinc-200"
                   >
                      <XMarkIcon className="w-5 h-5" />
                   </button>
                </div>
             </div>

             <div className="space-y-1 mb-4">
                <input 
                  type="range" 
                  min="0" 
                  max={duration || 100} 
                  value={currentTime}
                  onChange={handleSeek}
                  className="w-full h-2 bg-gray-200 dark:bg-zinc-800 rounded-lg appearance-none cursor-pointer accent-[#0ea5e9]"
                />
                <div className="flex justify-between text-[10px] font-black text-zinc-400 dark:text-zinc-500">
                   <span>{formatTime(currentTime)}</span>
                   <span>{formatTime(duration)}</span>
                </div>
             </div>

             <div className="flex items-center justify-center space-x-10">
                <button onClick={() => audioRef.current && (audioRef.current.currentTime -= 10)} className="text-zinc-300 dark:text-zinc-700 hover:text-[#0ea5e9] transition-colors active:scale-90">
                   <BackwardIcon className="w-8 h-8" />
                </button>
                <button 
                  onClick={togglePlay} 
                  disabled={isLoading}
                  className="w-16 h-16 bg-[#0ea5e9] rounded-full flex items-center justify-center text-white shadow-xl shadow-sky-500/30 active:scale-90 transition-transform disabled:opacity-50"
                >
                   {isPlaying ? <PauseIcon className="w-8 h-8" /> : <PlayIcon className="w-8 h-8 ml-1" />}
                </button>
                <button onClick={() => audioRef.current && (audioRef.current.currentTime += 10)} className="text-zinc-300 dark:text-zinc-700 hover:text-[#0ea5e9] transition-colors active:scale-90">
                   <ForwardIcon className="w-8 h-8" />
                </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

