  const [error, setError] = useState<{ message: string; details?: string } | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const t = TRANSLATIONS[language];

  const data = {
    monasteries: [
      { name: "Debre Damo (ደብረ ዳሞ)", info: "Founded by Abune Aregawi", prompt: "Spiritual history of Debre Damo monastery." },
      { name: "Axum Tsion (አክሱም ጽዮን)", info: "The Ark of Covenant", prompt: "History of Aksum Tsion." },
      { name: "Debre Libanos (ደብረ ሊባኖስ)", info: "St. Tekle Haymanot", prompt: "Life of Tekle Haymanot." },
      { name: "Waldiba (ዋልድባ)", info: "The Land of Monks", prompt: "Spiritual description of Waldiba." },
      { name: "Debre Bizen (ደብረ ቢዘን)", info: "Mount of Bizen", prompt: "History of Abune Filipos." }
    ],
    abnet: [
