      { name: "Qine Bet (ቅኔ ቤት)", info: "Poetry & Logic", prompt: "Ge'ez poetry and the 'Wax and Gold' philosophy." },
      { name: "Metsehaf Bet (መጽሐፍ ቤት)", info: "Interpretation", prompt: "Biblical interpretation tradition." }
    ],
    teachers: [
      { name: "Saint Yared (ቅዱስ ያሬድ)", info: "The Father of Music", prompt: "Biography of Saint Yared." },
      { name: "Tekle Haymanot (ተክለ ሃይማኖት)", info: "The Great Light", prompt: "Miracles of Abune Tekle Haymanot." }
    ],
    holidays: [
      { name: "Meskel (መስቀል)", info: "True Cross", prompt: "The history of finding the True Cross." },
      { name: "Timket (ጥምቀት)", info: "Epiphany", prompt: "Scriptural meaning of Timket." }
    ]
  };

  const togglePlay = () => {
    if (audioRef.current) {
      if (isPlaying) audioRef.current.pause();
      else audioRef.current.play().catch(console.error);
    }
  };

  const generateAudio = async (item: any) => {
    setPlayingItem(item);
    setIsLoading(true);
    setError(null);
    setAudioUrl(null);
    setIsPlaying(false);

    try {
      const genService = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const genResult = await genService.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate a narration for ${item.name} in ${language}. Tone: Spiritual and educational.`,
      });

      const textToSpeak = genResult.text;
      if (!textToSpeak) throw new Error("Narrative failed.");

      const ttsResponse = await genService.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: textToSpeak }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
        },
      });

      const base64Audio = ttsResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (!base64Audio) throw new Error("Audio synthesis failed.");

      const rawData = decodeBase64(base64Audio);
      const int16Data = new Int16Array(rawData.buffer);
      const wavBlob = pcmToWav(int16Data, 24000);
      setAudioUrl(URL.createObjectURL(wavBlob));
    } catch (err: any) {
      setError({ message: "Unable to start the history audio.", details: "Please check your connection." });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="max-w-xl mx-auto min-h-screen bg-white pb-72">
      {audioUrl && (
        <audio 
          ref={audioRef} 
          src={audioUrl} 
          onTimeUpdate={() => setCurrentTime(audioRef.current?.currentTime || 0)} 
          onDurationChange={() => setDuration(audioRef.current?.duration || 0)}
          onEnded={() => setIsPlaying(false)}
          onPlay={() => setIsPlaying(true)}
          onPause={() => setIsPlaying(false)}
        />
      )}

      <div className="bg-[#0ea5e9] p-6 pb-12 rounded-b-[3.5rem] shadow-lg text-white text-center">
        <MicrophoneIcon className="w-8 h-8 mx-auto mb-4" />
        <h1 className="text-3xl font-serif font-bold uppercase mb-8">{t.audio}</h1>
        <div className="flex flex-wrap justify-center gap-2">
          {LANGUAGES.map((lang) => (
            <button
              key={lang.id}
              onClick={() => setLanguage(lang.id as Language)}
              className={`py-2 px-4 rounded-xl text-[10px] font-black transition-all border ${
                language === lang.id ? 'bg-white text-[#0ea5e9]' : 'bg-sky-400/20 text-white border-sky-400/30'
              }`}
            >
              {lang.label}
            </button>
          ))}
        </div>
      </div>

      <div className="p-6 space-y-6 -mt-6">
        <div className="flex space-x-2 overflow-x-auto no-scrollbar pb-2">
          {Object.keys(data).map((cat) => (
            <button
              key={cat}
              onClick={() => setActiveTab(cat as any)}
              className={`flex-shrink-0 px-6 py-3 rounded-2xl text-[10px] font-black uppercase transition-all shadow-sm ${
                activeTab === cat ? 'bg-[#0ea5e9] text-white' : 'bg-gray-50 text-zinc-500 border border-gray-100'
              }`}
            >
              {t[cat] || cat}
            </button>
          ))}
        </div>

        {error && (
          <div className="bg-red-50 border border-red-100 p-6 rounded-[2rem] text-center animate-in zoom-in-95">
             <ExclamationCircleIcon className="w-10 h-10 text-red-500 mx-auto mb-4" />
             <p className="text-red-800 font-bold mb-1">{error.message}</p>
             <button onClick={() => playingItem && generateAudio(playingItem)} className="bg-red-500 text-white px-8 py-2 rounded-full font-black text-xs uppercase mt-4">Retry</button>
          </div>
        )}

        <div className="grid grid-cols-1 gap-4">
          {data[activeTab].map((item: any, idx: number) => (
            <button
              key={idx}
              disabled={isLoading}
              onClick={() => generateAudio(item)}
              className={`w-full flex items-center justify-between p-7 rounded-[2.5rem] border transition-all active:scale-[0.98] ${
                playingItem?.name === item.name 
                  ? 'bg-sky-50 border-sky-200' 
                  : 'bg-white border-gray-100 shadow-sm'
              }`}
            >
              <div className="flex items-center space-x-5">
                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center transition-all ${
                  playingItem?.name === item.name ? 'bg-[#0ea5e9] text-white shadow-md' : 'bg-gray-50 text-zinc-300'
                }`}>
                  {playingItem?.name === item.name && isLoading ? <ArrowPathIcon className="w-7 h-7 animate-spin" /> : 
                   playingItem?.name === item.name && isPlaying ? <PauseIcon className="w-7 h-7" /> : <PlayIcon className="w-7 h-7" />}
                </div>
                <div className="text-left">
                  <h3 className="text-lg font-black text-zinc-900">{item.name}</h3>
                  <p className="text-[10px] text-zinc-400 font-bold uppercase tracking-widest mt-1">{item.info}</p>
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>

      {(playingItem || isLoading) && (
        <div className="fixed bottom-24 left-4 right-4 z-[60] animate-in slide-in-from-bottom-10">
          <div className="max-w-xl mx-auto bg-white rounded-[2.5rem] shadow-2xl border border-sky-50 p-6">
             <div className="flex items-center justify-between mb-4">
                <div className="flex items-center space-x-3">
                   <div className="w-12 h-12 bg-[#0ea5e9] rounded-2xl flex items-center justify-center text-white shadow-lg">
                      {isLoading ? <ArrowPathIcon className="w-6 h-6 animate-spin" /> : <MicrophoneIcon className="w-6 h-6" />}
                   </div>
                   <div className="overflow-hidden">
                      <h4 className="text-sm font-black text-zinc-900 truncate w-32">{playingItem?.name || 'Preparing...'}</h4>
                      <p className="text-[10px] text-[#0ea5e9] font-black uppercase tracking-widest leading-none mt-1">{t[activeTab]}</p>
                   </div>
                </div>
                <div className="flex items-center space-x-1">
                   <button onClick={() => { setPlayingItem(null); setAudioUrl(null); }} className="p-2.5 text-zinc-300 hover:text-zinc-600"><XMarkIcon className="w-5 h-5" /></button>
                </div>
             </div>
             <div className="space-y-1 mb-4">
                <input type="range" min="0" max={duration || 100} value={currentTime} onChange={(e) => audioRef.current && (audioRef.current.currentTime = parseFloat(e.target.value))} className="w-full h-2 bg-sky-50 rounded-lg appearance-none cursor-pointer accent-[#0ea5e9]" />
             </div>
             <div className="flex items-center justify-center space-x-10">
                <button onClick={() => audioRef.current && (audioRef.current.currentTime -= 10)} className="text-zinc-200 hover:text-sky-400 transition-colors"><BackwardIcon className="w-8 h-8" /></button>
                <button onClick={togglePlay} disabled={isLoading} className="w-16 h-16 bg-[#0ea5e9] rounded-full flex items-center justify-center text-white shadow-xl shadow-sky-500/20 active:scale-90 transition-transform">
                   {isPlaying ? <PauseIcon className="w-8 h-8" /> : <PlayIcon className="w-8 h-8 ml-1" />}
                </button>
                <button onClick={() => audioRef.current && (audioRef.current.currentTime += 10)} className="text-zinc-200 hover:text-sky-400 transition-colors"><ForwardIcon className="w-8 h-8" /></button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

