      </div>

      {imageUrl && (selectedItem || isBible) && !loading && (
        <div className="relative w-full h-[35vh] overflow-hidden shadow-lg">
           <img src={imageUrl} className="w-full h-full object-cover" alt="Detail" />
           <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent"></div>
           <h2 className="absolute bottom-6 left-8 text-white text-3xl font-black uppercase drop-shadow-lg">{selectedItem || bookName}</h2>
        </div>
      )}

      <div className="px-8 pt-12">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-48"><div className="w-12 h-12 border-4 border-sky-100 border-t-[#0ea5e9] rounded-full animate-spin"></div></div>
        ) : selectedItem || isBible ? (
          <article className="text-zinc-800 pb-20 prose prose-sky max-w-none" style={{ fontSize: `${fontSize}px` }}>
            {detailContent.split('\n').map((line, i) => line.trim() ? <p key={i} className="mb-6 font-serif-church leading-relaxed text-justify opacity-90">{line}</p> : <div key={i} className="h-4" />)}
            <div className="mt-20 pt-10 border-t border-gray-50 text-center"><p className="text-[#0ea5e9] italic font-serif-church text-lg opacity-60 underline decoration-sky-100 underline-offset-8">{TRANSLATIONS[language].aboutUnderline}</p></div>
          </article>
        ) : (
          <div className="space-y-8">
            <div className="relative"><MagnifyingGlassIcon className="w-6 h-6 absolute left-6 top-1/2 -translate-y-1/2 text-zinc-300" /><input type="text" placeholder={t.search} value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full pl-16 pr-8 py-5 bg-white rounded-3xl border border-gray-100 focus:outline-none focus:ring-1 focus:ring-sky-200 font-bold shadow-sm" /></div>
            <div className="grid grid-cols-1 gap-5">{filteredList.map((item, idx) => (
              <button key={idx} onClick={() => handleSelectItem(item.name)} className="w-full flex items-center justify-between p-7 bg-white rounded-[2rem] border border-gray-50 shadow-sm hover:shadow-md hover:border-sky-50 transition-all text-left">
                <div className="flex-grow pr-4"><span className="text-xl font-black text-zinc-900 group-hover:text-[#0ea5e9] mb-2 block">{item.name}</span><p className="text-xs text-zinc-400 font-medium line-clamp-2">{item.description}</p></div>
                <ChevronRightIcon className="w-6 h-6 text-[#0ea5e9]" />
