      { name: "Waldiba (ዋልድባ)", info: "The spiritual desert of ascetics." },
      { name: "Debre Bizen (ደብረ ቢዘን)", info: "14th Century - Founded by Abune Filipos." },
      { name: "Daga Estifanos (ዳጋ እስጢፋኖስ)", info: "Royal mausoleum in Lake Tana." }
