                className={`flex-shrink-0 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all shadow-sm ${
                  activeTab === id ? 'bg-[#0ea5e9] text-white shadow-md' : 'bg-gray-50 text-zinc-500 border border-gray-100'
