            >
              <div className="flex items-center space-x-5">
                <div className="w-12 h-12 bg-sky-50 rounded-2xl flex items-center justify-center text-[#0ea5e9] font-black shadow-inner group-hover:bg-[#0ea5e9] group-hover:text-white transition-colors">
                  {i + 1}
