import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { UserIcon, MagnifyingGlassIcon, ArrowsUpDownIcon, HeartIcon as HeartOutline, CheckCircleIcon } from '@heroicons/react/24/outline';
import { HeartIcon as HeartSolid, ChevronLeftIcon as ChevronLeftSolid } from '@heroicons/react/24/solid';
import { Language } from '../types';
import { TRANSLATIONS } from '../constants';

const PrayerRequestPage: React.FC<{ language: Language }> = ({ language }) => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'ask' | 'pray'>('ask');
  const [name, setName] = useState('');
  const [request, setRequest] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [sortOrder, setSortOrder] = useState<'newest' | 'oldest'>('newest');
  const [submitted, setSubmitted] = useState(false);
  const [prayedSet, setPrayedSet] = useState<Set<string>>(new Set());

  const t = TRANSLATIONS[language];

  const initialRequests = [
    { id: '1', name: 'Wolete Maskal', time: '38m ago', request: 'Giving thanks for health and peace in our family.', timestamp: Date.now() - 38 * 60 * 1000, count: 12 },
    { id: '2', name: 'Wolde Senbet', time: '44m ago', request: 'Please pray for my spiritual journey as I study the Abnet school.', timestamp: Date.now() - 44 * 60 * 1000, count: 5 },
    { id: '3', name: 'Kidane Meheret', time: '1h ago', request: 'Asking for protection for our community.', timestamp: Date.now() - 60 * 60 * 1000, count: 24 }
  ];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !request) return;
    setSubmitted(true);
    setTimeout(() => {
      setSubmitted(false);
      setName('');
      setRequest('');
      setActiveTab('pray');
    }, 2000);
  };

  const togglePray = (id: string) => {
    const next = new Set(prayedSet);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setPrayedSet(next);
  };

  const sortedAndFiltered = useMemo(() => {
    let res = initialRequests.filter(r => 
      r.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
      r.request.toLowerCase().includes(searchQuery.toLowerCase())
    );
    return res.sort((a, b) => sortOrder === 'newest' ? b.timestamp - a.timestamp : a.timestamp - b.timestamp);
  }, [searchQuery, sortOrder]);

  return (
    <div className="min-h-screen bg-white text-black pb-32 max-w-xl mx-auto">
      <div className="bg-[#0ea5e9] p-4 pt-10 flex flex-col items-center text-white relative shadow-md rounded-b-[2rem]">
        <button onClick={() => navigate(-1)} className="absolute left-4 top-10 p-2 hover:bg-white/20 rounded-full transition-colors text-white">
          <ChevronLeftSolid className="w-5 h-5" />
        </button>
        <h1 className="text-lg font-black tracking-tight mb-4 uppercase">{t.prayerRequest}</h1>
        <div className="flex w-full relative bg-sky-400/20 rounded-xl p-1">
          <button onClick={() => setActiveTab('ask')} className={`flex-1 py-2 text-xs font-black transition-all rounded-lg ${activeTab === 'ask' ? 'bg-white text-[#0ea5e9] shadow-sm' : 'text-white'}`}>{t.ask}</button>
          <button onClick={() => setActiveTab('pray')} className={`flex-1 py-2 text-xs font-black transition-all rounded-lg ${activeTab === 'pray' ? 'bg-white text-[#0ea5e9] shadow-sm' : 'text-white'}`}>{t.pray}</button>
        </div>
      </div>

      <div className="p-6 pt-10">
        {submitted ? (
          <div className="flex flex-col items-center justify-center py-20 space-y-4 animate-in zoom-in-90">
             <CheckCircleIcon className="w-20 h-20 text-[#0ea5e9]" />
             <h2 className="text-2xl font-black text-zinc-900">Request Sent</h2>
             <p className="text-zinc-400 font-bold uppercase tracking-widest text-xs">The community will pray for you.</p>
          </div>
        ) : activeTab === 'ask' ? (
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-zinc-300 ml-1 tracking-widest">{t.name}</label>
              <input 
                type="text" 
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="Enter your name" 
                className="w-full p-5 bg-white border border-gray-100 rounded-2xl text-sm font-bold shadow-sm outline-none focus:ring-1 focus:ring-sky-200 transition-all" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-zinc-300 ml-1 tracking-widest">{t.request}</label>
              <textarea 
                value={request}
                onChange={(e) => setRequest(e.target.value)}
                placeholder="How can we pray for you?" 
                className="w-full p-5 h-44 bg-white border border-gray-100 rounded-2xl text-sm font-bold shadow-sm outline-none focus:ring-1 focus:ring-sky-200 transition-all resize-none" 
              />
            </div>
            <button 
              type="submit" 
              className="w-full py-5 rounded-2xl text-lg font-black bg-[#0ea5e9] text-white shadow-xl shadow-sky-500/20 active:scale-95 transition-transform"
            >
              {t.submit}
            </button>
          </form>
        ) : (
          <div className="space-y-6">
            <div className="flex items-center space-x-3">
              <div className="relative flex-grow">
                <MagnifyingGlassIcon className="w-4 h-4 absolute left-4 top-1/2 -translate-y-1/2 text-zinc-300" />
                <input 
                  type="text" 
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  placeholder="Search prayers" 
                  className="w-full pl-11 pr-4 py-4 bg-white rounded-2xl border border-gray-100 text-xs font-black shadow-sm outline-none" 
                />
              </div>
              <button onClick={() => setSortOrder(sortOrder === 'newest' ? 'oldest' : 'newest')} className="flex items-center px-4 py-4 bg-sky-50 border border-sky-100 rounded-2xl text-[#0ea5e9] font-black uppercase text-[10px]">
                <ArrowsUpDownIcon className="w-4 h-4 mr-2" />
                {sortOrder === 'newest' ? t.newest : t.oldest}
              </button>
            </div>
            <div className="space-y-4">
              {sortedAndFiltered.map((item) => (
                <div key={item.id} className="bg-white rounded-[2rem] p-6 border border-gray-50 flex items-start space-x-5 shadow-sm hover:shadow-md transition-shadow">
                  <div className="w-12 h-12 bg-sky-50 rounded-full flex items-center justify-center text-[#0ea5e9] shadow-inner"><UserIcon className="w-6 h-6" /></div>
                  <div className="flex-grow">
                    <div className="flex justify-between items-center mb-2">
                      <h4 className="text-sm font-black text-zinc-800">{item.name}</h4>
                      <span className="text-[10px] font-bold text-zinc-300">{item.time}</span>
                    </div>
                    <p className="text-xs text-zinc-500 leading-relaxed font-medium mb-4">{item.request}</p>
                    <button 
                      onClick={() => togglePray(item.id)}
                      className={`flex items-center space-x-2 px-5 py-2.5 rounded-full active:scale-95 transition-all ${prayedSet.has(item.id) ? 'bg-[#0ea5e9] text-white' : 'bg-sky-50 text-[#0ea5e9]'}`}
                    >
                      {prayedSet.has(item.id) ? <HeartSolid className="w-4 h-4" /> : <HeartOutline className="w-4 h-4" />}
                      <span className="text-[10px] font-black uppercase">{prayedSet.has(item.id) ? 'Prayed' : 'Pray'}</span>
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default PrayerRequestPage;

import React, { useState, useEffect, useMemo } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { ChevronLeftIcon, MagnifyingGlassIcon, ChevronRightIcon } from '@heroicons/react/24/solid';
import { GoogleGenAI, Type } from '@google/genai';
import { Language } from '../types';
import { TRANSLATIONS } from '../constants';

const ContentDetail: React.FC<any> = ({ language, fontSize, isBible }) => {
  const { categoryId, bookName } = useParams<{ categoryId?: string; bookName?: string }>();
  const navigate = useNavigate();
  const location = useLocation();
  const t = TRANSLATIONS[language];

  const [list, setList] = useState<any[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedItem, setSelectedItem] = useState<string | null>(null);
  const [detailContent, setDetailContent] = useState<string>('');
  const [imageUrl, setImageUrl] = useState<string>('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const queryParam = new URLSearchParams(location.search).get('query');
    if (queryParam) {
      handleSelectItem(queryParam);
    } else if (isBible) {
      fetchBibleDetail();
    } else {
      fetchCategoryList();
    }
  }, [categoryId, bookName, language, isBible, location.search]);

  const fetchBibleDetail = async () => {
    setLoading(true);
    try {
      const genService = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const promptText = `Provide a comprehensive theological and historical overview of the Bible book "${bookName}" in ${language}. 
      Focus on its importance in the Ethiopian Orthodox Tewahedo Church. Use Markdown.`;
      const response = await genService.models.generateContent({ model: 'gemini-3-flash-preview', contents: promptText });
      setDetailContent(response.text || '');
      setImageUrl(`https://images.unsplash.com/photo-1507434965515-61970f2bd7c6?q=80&w=1200`);
    } catch (e) { 
      console.error(e); 
      setDetailContent("Unable to load history at this moment.");
    } finally { setLoading(false); }
  };

  const fetchCategoryList = async () => {
    if (!categoryId || categoryId === 'search') return;
    setLoading(true);
    try {
      const genService = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const promptText = `Provide 10 major spiritual entries for the category "${categoryId}" in ${language}. 
      Return ONLY valid JSON: [{"name": "...", "description": "...", "searchTerms": "..."}]`;

      const response = await genService.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: promptText,
        config: { 
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                searchTerms: { type: Type.STRING }
              },
              required: ["name", "description", "searchTerms"]
            }
          }
        }
      });
      setList(JSON.parse(response.text || '[]'));
    } catch (e) { 
      console.error(e); 
      setList([]);
    } finally { setLoading(false); }
  };

  const handleSelectItem = async (itemName: string) => {
    setSelectedItem(itemName);
    setLoading(true);
    try {
      const genService = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const promptText = `Write an EXTREMELY DETAILED history of "${itemName}" in ${language} for the Ethiopian Orthodox Church tradition. 
      Use Markdown headers. At the end, add 'IMAGE_TAGS: [3 descriptive English keywords]'.`;

      const response = await genService.models.generateContent({ model: 'gemini-3-flash-preview', contents: promptText });
      const text = response.text || '';

      const tagsMatch = text.match(/IMAGE_TAGS:\s*(.*)/i);
      const cleanContent = text.replace(/IMAGE_TAGS:\s*(.*)/i, '').trim();
      setDetailContent(cleanContent);

      let keywords = tagsMatch ? tagsMatch[1] : itemName;
      setImageUrl(`https://loremflickr.com/1200/800/${encodeURIComponent(keywords.replace(/[\[\]]/g, ''))}/all`);
    } catch (e) { 
      console.error(e); 
      setDetailContent("Could not fetch details. Please try again.");
    } finally { setLoading(false); }
  };

  const filteredList = useMemo(() => {
    return list.filter(item => 
      item.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
      item.description.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [list, searchQuery]);

  return (
    <div className="max-w-xl mx-auto min-h-screen bg-white pb-32 shadow-xl">
      <div className="sticky top-0 bg-[#0ea5e9] text-white px-6 py-10 flex items-center shadow-lg z-50 rounded-b-[2.5rem]">
        <button onClick={() => selectedItem ? setSelectedItem(null) : navigate(-1)} className="mr-5 p-2.5 hover:bg-white/20 rounded-full text-white transition-colors">
          <ChevronLeftIcon className="w-6 h-6" />
        </button>
        <h1 className="text-2xl font-black truncate uppercase leading-none">{selectedItem || bookName || t[categoryId] || 'History'}</h1>
      </div>

      {imageUrl && (selectedItem || isBible) && !loading && (
        <div className="relative w-full h-[35vh] overflow-hidden shadow-lg animate-in fade-in duration-700">
           <img src={imageUrl} className="w-full h-full object-cover brightness-95" alt="Detail" />
           <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent"></div>
           <h2 className="absolute bottom-6 left-8 right-8 text-white text-3xl font-black uppercase drop-shadow-xl tracking-tighter">{selectedItem || bookName}</h2>
        </div>
      )}

      <div className="px-8 pt-12">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-48">
            <div className="w-12 h-12 border-4 border-sky-100 border-t-[#0ea5e9] rounded-full animate-spin"></div>
            <p className="mt-4 font-black uppercase tracking-widest text-[#0ea5e9] text-xs animate-pulse">Loading Wisdom</p>
          </div>
        ) : selectedItem || isBible ? (
          <article className="text-zinc-800 pb-20 prose prose-sky max-w-none" style={{ fontSize: `${fontSize}px` }}>
            {detailContent.split('\n').map((line, i) => {
              const trimmed = line.trim();
              if (!trimmed) return <div key={i} className="h-4" />;
              if (trimmed.startsWith('#')) return <h3 key={i} className="text-[#0ea5e9] font-black text-2xl mb-4 mt-8 uppercase">{trimmed.replace(/^#+\s*/, '')}</h3>;
              return <p key={i} className="mb-6 font-serif-church leading-relaxed text-justify opacity-90">{trimmed}</p>;
            })}
            <div className="mt-20 pt-10 border-t border-gray-100 text-center">
              <p className="text-[#0ea5e9] italic font-serif-church text-lg opacity-60 underline decoration-sky-100 underline-offset-8">
                {TRANSLATIONS[language].aboutUnderline}
              </p>
            </div>
          </article>
        ) : (
          <div className="space-y-8">
            <div className="relative">
              <MagnifyingGlassIcon className="w-6 h-6 absolute left-6 top-1/2 -translate-y-1/2 text-zinc-300" />
              <input 
                type="text" 
                placeholder={t.search} 
                value={searchQuery} 
                onChange={(e) => setSearchQuery(e.target.value)} 
                className="w-full pl-16 pr-8 py-5 bg-white rounded-3xl border border-gray-100 focus:outline-none focus:ring-1 focus:ring-sky-200 font-bold shadow-sm" 
              />
            </div>
            <div className="grid grid-cols-1 gap-5">
              {filteredList.map((item, idx) => (
                <button 
                  key={idx} 
                  onClick={() => handleSelectItem(item.name)} 
                  className="w-full flex items-center justify-between p-7 bg-white rounded-[2rem] border border-gray-50 shadow-sm hover:shadow-md hover:border-sky-50 transition-all text-left group"
                >
                  <div className="flex-grow pr-4">
                    <span className="text-xl font-black text-zinc-900 group-hover:text-[#0ea5e9] mb-2 block transition-colors">{item.name}</span>
                    <p className="text-xs text-zinc-400 font-medium line-clamp-2">{item.description}</p>
                  </div>
                  <ChevronRightIcon className="w-6 h-6 text-[#0ea5e9] group-hover:translate-x-1 transition-transform" />
                </button>
              ))}
              {filteredList.length === 0 && <p className="text-center py-20 opacity-30 font-bold">No entries found.</p>}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default ContentDetail;

