              onClick={() => setShowCategories(false)}
              className="text-[11px] font-black text-zinc-400 dark:text-zinc-600 hover:text-sky-600 transition-colors uppercase tracking-widest border border-gray-100 dark:border-zinc-800 px-4 py-2 rounded-full bg-white dark:bg-zinc-900 shadow-sm"
            >
              {t.changeLanguage}
            </button>
          </div>

          <div className="relative group">
            <MagnifyingGlassIcon className="w-5 h-5 absolute left-4 top-1/2 -translate-y-1/2 text-zinc-300 dark:text-zinc-700 group-focus-within:text-[#0ea5e9]" />
            <input 
              type="text" 
              placeholder="Search" 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-12 pr-4 py-4 bg-white dark:bg-zinc-900 text-zinc-900 dark:text-zinc-100 rounded-2xl border border-gray-100 dark:border-zinc-800 focus:outline-none focus:ring-1 focus:ring-sky-500/30 font-bold text-sm shadow-sm"
            />
          </div>

          <div className="space-y-4">
            {filteredCategories.map((cat) => (
              <button
                key={cat.id}
                onClick={() => navigate(`/content/${cat.id}`)}
                className="w-full flex items-center justify-between p-6 bg-white dark:bg-zinc-900 rounded-[1.5rem] shadow-sm border border-gray-50 dark:border-zinc-800 hover:border-sky-100 dark:hover:border-sky-900 transition-all group"
              >
                <div className="text-left">
                  <span className="text-lg font-black text-zinc-900 dark:text-zinc-100 group-hover:text-[#0ea5e9] leading-tight tracking-tight">
                    {cat.title[language]}
                  </span>
                </div>
                <div className="text-[#0ea5e9] transition-transform group-hover:translate-x-1">
                  <ChevronRightIcon className="w-6 h-6" strokeWidth={3} />
                </div>
              </button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default Home;
